export enum TicketStatus {
  PENDING = 'Pendiente',
  IN_PROGRESS = 'En Progreso',
  RESOLVED = 'Resuelto'
}

export enum TicketType {
  GENERAL = 'Servicios Generales',
  IT = 'Informática'
}

export interface Ticket {
  id: number;
  tipo: TicketType;
  descripcion: string;
  estado: TicketStatus;
  fecha: string;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

import { Ticket, TicketStatus, TicketType } from '../types';

// Mock storage key
const STORAGE_KEY = 'teams_tickets_db';

/**
 * Mocks the API calls to the Node.js/SQLite backend for the browser demo.
 * In a real deployment, these would use fetch() to call /api/tickets
 */
export const ticketService = {
  getTickets: async (): Promise<Ticket[]> => {
    // Simulate network delay
    await new Promise(resolve => setTimeout(resolve, 500));

    const stored = localStorage.getItem(STORAGE_KEY);
    if (!stored) return [];

    try {
      const tickets = JSON.parse(stored);
      // Sort by date desc
      return tickets.sort((a: Ticket, b: Ticket) => 
        new Date(b.fecha).getTime() - new Date(a.fecha).getTime()
      );
    } catch (e) {
      console.error("Failed to parse tickets", e);
      return [];
    }
  },

  createTicket: async (ticket: Omit<Ticket, 'id' | 'estado' | 'fecha'>): Promise<Ticket> => {
    await new Promise(resolve => setTimeout(resolve, 600));

    const stored = localStorage.getItem(STORAGE_KEY);
    const tickets: Ticket[] = stored ? JSON.parse(stored) : [];

    const newTicket: Ticket = {
      id: Date.now(), // Mock ID
      tipo: ticket.tipo,
      descripcion: ticket.descripcion,
      estado: TicketStatus.PENDING,
      fecha: new Date().toISOString()
    };

    tickets.push(newTicket);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(tickets));

    return newTicket;
  },

  updateTicketStatus: async (id: number, status: TicketStatus): Promise<Ticket | null> => {
    await new Promise(resolve => setTimeout(resolve, 400));

    const stored = localStorage.getItem(STORAGE_KEY);
    if (!stored) return null;

    const tickets: Ticket[] = JSON.parse(stored);
    const index = tickets.findIndex(t => t.id === id);

    if (index === -1) return null;

    tickets[index].estado = status;
    localStorage.setItem(STORAGE_KEY, JSON.stringify(tickets));

    return tickets[index];
  }
};

import { GoogleGenAI } from "@google/genai";

// IMPORTANT: In a real production app, never expose API keys on the client side.
// This should be proxied through the Node.js backend.
// For this demo, we assume the environment variable is available or the user is aware.
const apiKey = process.env.API_KEY || 'YOUR_API_KEY_HERE';
const ai = new GoogleGenAI({ apiKey });

export const geminiService = {
  /**
   * Fast analysis of ticket content to suggest category or quick fixes
   * Uses Gemini Flash Lite for low latency
   */
  analyzeTicket: async (description: string): Promise<string> => {
    if (!description || description.length < 5) return "";

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-flash-lite-latest',
        contents: `Analyze this support ticket description and provide a very short, 1-sentence potential cause or category suggestion.

        Description: ${description}`,
      });
      return response.text || "";
    } catch (error) {
      console.error("Gemini analysis failed:", error);
      return "";
    }
  },

  /**
   * Complex reasoning for the support assistant chat
   * Uses Gemini Pro
   */
  chatWithSupport: async (message: string, history: any[] = []): Promise<string> => {
    try {
      const chat = ai.chats.create({
        model: 'gemini-3-pro-preview',
        history: history,
        config: {
          systemInstruction: "You are a helpful IT Support Assistant for a company. Help users resolve basic technical issues or guide them to create a ticket. Be concise and professional.",
        },
      });

      const result = await chat.sendMessage({ message });
      return result.text || "I'm having trouble connecting to the support brain right now.";
    } catch (error) {
      console.error("Gemini chat failed:", error);
      return "Sorry, I encountered an error while processing your request.";
    }
  },

  /**
   * Vision capabilities to analyze screenshots of errors
   * Uses Gemini Pro Vision
   */
  analyzeScreenshot: async (base64Image: string): Promise<string> => {
    try {
      // Remove data URL prefix if present
      const cleanBase64 = base64Image.replace(/^data:image\/(png|jpeg|jpg);base64,/, '');

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: {
          parts: [
            {
              inlineData: {
                mimeType: 'image/png',
                data: cleanBase64
              }
            },
            {
              text: "Analyze this screenshot. If it contains an error message, extract it. Describe the technical issue seen in the image suitable for an IT support ticket description."
            }
          ]
        }
      });
      return response.text || "";
    } catch (error) {
      console.error("Gemini vision failed:", error);
      throw error;
    }
  }
};

import React from 'react';
import { Ticket, TicketStatus } from '../types';
import { ICONS } from '../constants';

interface TicketListProps {
  tickets: Ticket[];
  onStatusChange: (id: number, status: TicketStatus) => void;
  isLoading: boolean;
}

const statusColors = {
  [TicketStatus.PENDING]: 'bg-red-100 text-red-800 border-red-200',
  [TicketStatus.IN_PROGRESS]: 'bg-yellow-100 text-yellow-800 border-yellow-200',
  [TicketStatus.RESOLVED]: 'bg-green-100 text-green-800 border-green-200',
};

export const TicketList: React.FC<TicketListProps> = ({ tickets, onStatusChange, isLoading }) => {
  if (isLoading) {
    return (
      <div className="flex justify-center items-center py-12">
        <div className="text-teams-purple animate-spin">
           <ICONS.Spinner />
        </div>
        <span className="ml-2 text-gray-500">Loading tickets...</span>
      </div>
    );
  }

  if (tickets.length === 0) {
    return (
      <div className="text-center py-12 bg-white rounded-lg border border-gray-200">
        <p className="text-gray-500">No active tickets found.</p>
        <p className="text-sm text-gray-400 mt-1">Create a new ticket to get started.</p>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {tickets.map((ticket) => (
        <div 
          key={ticket.id} 
          className="bg-white p-4 rounded-lg border border-gray-200 shadow-sm hover:shadow-md transition-shadow duration-200"
        >
          <div className="flex justify-between items-start">
            <div>
              <div className="flex items-center space-x-2 mb-1">
                <span className="text-xs font-mono text-gray-400">#{ticket.id}</span>
                <span className={`px-2 py-0.5 text-xs rounded-full border font-medium ${statusColors[ticket.estado]}`}>
                  {ticket.estado}
                </span>
                <span className="text-xs text-gray-400 bg-gray-100 px-2 py-0.5 rounded">
                  {ticket.tipo}
                </span>
              </div>
              <h3 className="text-gray-800 font-medium mt-1">{ticket.descripcion}</h3>
              <p className="text-xs text-gray-400 mt-2">
                Created: {new Date(ticket.fecha).toLocaleString()}
              </p>
            </div>

            <div className="flex flex-col space-y-2 ml-4">
               {/* Action Buttons based on current state */}
               {ticket.estado === TicketStatus.PENDING && (
                 <button
                   onClick={() => onStatusChange(ticket.id, TicketStatus.IN_PROGRESS)}
                   className="text-xs bg-teams-purple text-white px-3 py-1 rounded hover:bg-opacity-90 transition-colors"
                 >
                   Start Work
                 </button>
               )}

               {ticket.estado === TicketStatus.IN_PROGRESS && (
                 <button
                   onClick={() => onStatusChange(ticket.id, TicketStatus.RESOLVED)}
                   className="text-xs bg-green-600 text-white px-3 py-1 rounded hover:bg-green-700 transition-colors"
                 >
                   Resolve
