               )}

               {ticket.estado === TicketStatus.RESOLVED && (
                 <button
                   onClick={() => onStatusChange(ticket.id, TicketStatus.PENDING)}
                   className="text-xs text-gray-500 hover:text-gray-700 underline"
                 >
                   Reopen
                 </button>
               )}
            </div>
          </div>
        </div>
      ))}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { geminiService } from '../services/geminiService';
import { ICONS } from '../constants';
import { ChatMessage } from '../types';

export const ChatAssistant: React.FC = () => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: '1',
      role: 'model',
      text: 'Hi! I am the Support AI Assistant. How can I help you today before you create a ticket?',
      timestamp: Date.now()
    }
  ]);
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    try {
      // Convert internal history format to Gemini format if needed, 
      // but for simplicity we'll just send the last message here 
      // or implement full history in service if needed.
      const responseText = await geminiService.chatWithSupport(userMsg.text);

      const aiMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText,
        timestamp: Date.now()
      };

      setMessages(prev => [...prev, aiMsg]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="flex flex-col h-[500px] bg-white rounded-lg border border-gray-200 shadow-sm">
      <div className="p-4 border-b border-gray-100 bg-gray-50 rounded-t-lg flex items-center">
        <div className="text-teams-purple mr-2"><ICONS.Sparkles /></div>
        <h3 className="font-semibold text-gray-700">AI Assistant</h3>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div 
              className={`max-w-[80%] rounded-lg p-3 text-sm ${
                msg.role === 'user' 
                  ? 'bg-teams-purple text-white rounded-br-none' 
                  : 'bg-gray-100 text-gray-800 rounded-bl-none'
              }`}
            >
              {msg.text}
            </div>
          </div>
        ))}
        {isTyping && (
           <div className="flex justify-start">
             <div className="bg-gray-100 rounded-lg rounded-bl-none p-3 flex items-center space-x-1">
               <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"></div>
               <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-100"></div>
               <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-200"></div>
             </div>
           </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-3 border-t border-gray-100">
        <div className="flex space-x-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Type your issue..."
            className="flex-1 border border-gray-300 rounded-md px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-teams-purple"
          />
          <button
            onClick={handleSend}
            disabled={isTyping || !input.trim()}
            className="bg-teams-purple text-white p-2 rounded-md hover:bg-opacity-90 disabled:opacity-50"
          >
            <ICONS.Chat />
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { TicketType } from '../types';
import { ICONS } from '../constants';
import { geminiService } from '../services/geminiService';

interface TicketFormProps {
  onSubmit: (data: { tipo: TicketType; descripcion: string }) => Promise<void>;
  onCancel: () => void;
}

export const TicketForm: React.FC<TicketFormProps> = ({ onSubmit, onCancel }) => {
  const [tipo, setTipo] = useState<TicketType>(TicketType.IT);
  const [descripcion, setDescripcion] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [aiSuggestion, setAiSuggestion] = useState('');

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!descripcion.trim()) return;

    setIsSubmitting(true);
    try {
      await onSubmit({ tipo, descripcion });
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsAnalyzing(true);
    setAiSuggestion('');

    try {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64 = reader.result as string;
        try {
          const analysis = await geminiService.analyzeScreenshot(base64);
          setDescripcion(prev => (prev ? prev + '\n\n' : '') + "[AI Analysis]: " + analysis);
          setAiSuggestion("Screenshot analyzed successfully. Description updated.");
        } catch (err) {
          setAiSuggestion("Failed to analyze image.");
        } finally {
          setIsAnalyzing(false);
        }
      };
      reader.readAsDataURL(file);
    } catch (err) {
      console.error(err);
      setIsAnalyzing(false);
    }
  };

  const handleSmartCheck = async () => {
    if (descripcion.length < 5) return;
    setIsAnalyzing(true);
    try {
      const suggestion = await geminiService.analyzeTicket(descripcion);
      setAiSuggestion(suggestion);
    } catch (e) {
      // ignore
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="bg-white p-6 rounded-lg border border-gray-200 shadow-sm">
      <h2 className="text-lg font-semibold mb-4 text-teams-dark">Create New Ticket</h2>

      <div className="mb-4">
        <label className="block text-sm font-medium text-gray-700 mb-1">Type</label>
        <select
          value={tipo}
          onChange={(e) => setTipo(e.target.value as TicketType)}
          className="w-full border border-gray-300 rounded-md px-3 py-2 focus:ring-2 focus:ring-teams-purple focus:outline-none"
        >
          {Object.values(TicketType).map((t) => (
            <option key={t} value={t}>{t}</option>
          ))}
        </select>
      </div>

      <div className="mb-4">
        <label className="block text-sm font-medium text-gray-700 mb-1">
          Description
          {isAnalyzing && <span className="ml-2 text-xs text-teams-purple animate-pulse">AI Analyzing...</span>}
        </label>
        <textarea
          value={descripcion}
          onChange={(e) => setDescripcion(e.target.value)}
          onBlur={handleSmartCheck}
          rows={4}
          className="w-full border border-gray-300 rounded-md px-3 py-2 focus:ring-2 focus:ring-teams-purple focus:outline-none"
          placeholder="Describe your issue..."
        />
        {aiSuggestion && (
          <div className="mt-2 p-2 bg-blue-50 text-blue-800 text-xs rounded border border-blue-100 flex items-start">
            <span className="mr-1 mt-0.5"><ICONS.Sparkles /></span>
            <span>{aiSuggestion}</span>
          </div>
        )}
      </div>

      <div className="mb-6">
        <button
          type="button"
          onClick={() => fileInputRef.current?.click()}
          disabled={isAnalyzing}
          className="flex items-center text-sm text-teams-purple hover:text-purple-800 transition-colors"
        >
          <span className="mr-1"><ICONS.Image /></span>
          Upload Screenshot (AI Analysis)
        </button>
        <input
          type="file"
          ref={fileInputRef}
          className="hidden"
          accept="image/*"
          onChange={handleImageUpload}
        />
      </div>

      <div className="flex justify-end space-x-3">
        <button
          type="button"
          onClick={onCancel}
          className="px-4 py-2 text-sm text-gray-600 hover:bg-gray-100 rounded-md transition-colors"
        >
          Cancel
        </button>
        <button
          type="submit"
          disabled={isSubmitting || isAnalyzing}
          className="bg-teams-purple text-white px-4 py-2 rounded-md hover:bg-opacity-90 transition-colors disabled:opacity-50 flex items-center"
        >
          {isSubmitting ? <ICONS.Spinner /> : 'Create Ticket'}
        </button>
      </div>
    </form>
  );
};

import React, { useState, useEffect } from 'react';
import { TicketList } from './components/TicketList';
import { TicketForm } from './components/TicketForm';
import { ChatAssistant } from './components/ChatAssistant';
import { ticketService } from './services/ticketService';
import { Ticket, TicketStatus, TicketType } from './types';
import { ICONS, TEAMS_THEME_COLOR } from './constants';

enum Tab {
  LIST = 'list',
  NEW = 'new',
  CHAT = 'chat'
}

export default function App() {
  const [activeTab, setActiveTab] = useState<Tab>(Tab.LIST);
  const [tickets, setTickets] = useState<Ticket[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  const fetchTickets = async () => {
    setIsLoading(true);
    try {
      const data = await ticketService.getTickets();
      setTickets(data);
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchTickets();
  }, []);

  const handleCreateTicket = async (data: { tipo: TicketType; descripcion: string }) => {
    try {
      await ticketService.createTicket(data);
      await fetchTickets();
      setActiveTab(Tab.LIST);
    } catch (e) {
      alert("Error creating ticket");
    }
  };

  const handleStatusChange = async (id: number, status: TicketStatus) => {
    try {
      const updated = await ticketService.updateTicketStatus(id, status);
      if (updated) {
        setTickets(prev => prev.map(t => t.id === id ? updated : t));
      }
    } catch (e) {
      alert("Error updating status");
    }
  };

  return (
    <div className="min-h-screen bg-teams-light text-teams-dark font-sans">
      {/* Header */}
      <header className="bg-white border-b border-gray-200 px-6 py-4 flex items-center justify-between shadow-sm sticky top-0 z-10">
        <div className="flex items-center space-x-3">
          <div className="bg-teams-purple p-1.5 rounded text-white">
            <ICONS.Ticket />
          </div>
          <h1 className="text-xl font-semibold text-teams-purple tracking-tight">Support Tickets</h1>
        </div>
        <div className="text-sm text-gray-500">
          Teams Integrated App
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-4xl mx-auto p-6">

        {/* Navigation Tabs */}
        <div className="flex space-x-1 border-b border-gray-300 mb-6">
          <button
            onClick={() => setActiveTab(Tab.LIST)}
            className={`px-4 py-2 text-sm font-medium transition-colors border-b-2 ${
              activeTab === Tab.LIST 
                ? 'border-teams-purple text-teams-purple' 
                : 'border-transparent text-gray-500 hover:text-gray-700'
            }`}
          >
            All Tickets
          </button>
          <button
            onClick={() => setActiveTab(Tab.NEW)}
            className={`px-4 py-2 text-sm font-medium transition-colors border-b-2 ${
              activeTab === Tab.NEW 
                ? 'border-teams-purple text-teams-purple' 
                : 'border-transparent text-gray-500 hover:text-gray-700'
            }`}
          >
            New Ticket
          </button>
          <button
            onClick={() => setActiveTab(Tab.CHAT)}
            className={`px-4 py-2 text-sm font-medium transition-colors border-b-2 flex items-center space-x-1 ${
              activeTab === Tab.CHAT
                ? 'border-teams-purple text-teams-purple' 
                : 'border-transparent text-gray-500 hover:text-gray-700'
            }`}
          >
             <ICONS.Sparkles />
             <span>AI Assistant</span>
          </button>
        </div>

        {/* Tab Content */}
        <div className="transition-all duration-300 ease-in-out">
          {activeTab === Tab.LIST && (
            <>
              <div className="flex justify-between items-center mb-4">
                <h2 className="text-lg font-bold text-gray-700">My Tickets</h2>
                <button 
                   onClick={fetchTickets}
                   className="text-sm text-teams-purple hover:underline"
                >
                  Refresh
                </button>
              </div>
              <TicketList 
                tickets={tickets} 
                onStatusChange={handleStatusChange} 
                isLoading={isLoading} 
              />
            </>
          )}

          {activeTab === Tab.NEW && (
            <TicketForm 
              onSubmit={handleCreateTicket} 
              onCancel={() => setActiveTab(Tab.LIST)} 
            />
          )}

          {activeTab === Tab.CHAT && (
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="md:col-span-2">
                 <ChatAssistant />
              </div>
              <div className="bg-white p-4 rounded-lg border border-gray-200 h-fit">
                <h3 className="font-semibold mb-2 text-sm">About AI Support</h3>
                <p className="text-xs text-gray-500 mb-3">
                  Our AI Assistant uses <strong>Gemini Pro</strong> to help diagnose issues before you submit a ticket.
                </p>
                <ul className="text-xs text-gray-500 list-disc list-inside space-y-1">
                  <li>Ask technical questions</li>
                  <li>Troubleshoot software errors</li>
                  <li>Get instant policy info</li>
                </ul>
              </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
}

