                   <button
                     onClick={() => onStatusChange(ticket.id, TicketStatus.RESOLVED)}
                     className="text-xs bg-green-600 text-white px-3 py-1 rounded hover:bg-green-700 transition-colors whitespace-nowrap"
                   >
                     Resolve
                   </button>
                 )}

                 {ticket.estado === TicketStatus.RESOLVED && (
                   <button
                     onClick={() => onStatusChange(ticket.id, TicketStatus.PENDING)}
                     className="text-xs text-gray-500 hover:text-gray-700 underline whitespace-nowrap"
                   >
                     Reopen
                   </button>
                 )}
              </div>
            )}
          </div>
        </div>
      ))}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { TicketList } from './components/TicketList';
import { TicketForm } from './components/TicketForm';
import { ChatAssistant } from './components/ChatAssistant';
import { AdminPanel } from './components/AdminPanel';
import { LoginScreen } from './components/LoginScreen';
import { ticketService } from './services/ticketService';
import { Ticket, TicketStatus, TicketType, User, UserRole } from './types';
import { ICONS, TEAMS_THEME_COLOR } from './constants';

enum Tab {
  LIST = 'list',
  NEW = 'new',
  CHAT = 'chat',
  ADMIN = 'admin'
}

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<Tab>(Tab.LIST);
  const [tickets, setTickets] = useState<Ticket[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  const fetchTickets = async () => {
    setIsLoading(true);
    try {
      const data = await ticketService.getTickets();
      setTickets(data);
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (user) {
      fetchTickets();
    }
  }, [user]);

  const handleCreateTicket = async (data: { tipo: TicketType; descripcion: string }) => {
    try {
      await ticketService.createTicket(data);
      await fetchTickets();
      setActiveTab(Tab.LIST);
    } catch (e) {
      alert("Error creating ticket");
    }
  };

  const handleStatusChange = async (id: number, status: TicketStatus) => {
    try {
      const updated = await ticketService.updateTicketStatus(id, status);
      if (updated) {
        setTickets(prev => prev.map(t => t.id === id ? updated : t));
      }
    } catch (e) {
      alert("Error updating status");
    }
  };

  const handleLogout = () => {
    setUser(null);
    setActiveTab(Tab.LIST);
  };

  if (!user) {
    return <LoginScreen onLogin={setUser} />;
  }

  const isAdmin = user.role === UserRole.ADMIN;

  return (
    <div className="min-h-screen bg-teams-light text-teams-dark font-sans">
      {/* Header */}
      <header className="bg-white border-b border-gray-200 px-6 py-4 flex items-center justify-between shadow-sm sticky top-0 z-10">
        <div className="flex items-center space-x-3">
          <div className="bg-teams-purple p-1.5 rounded text-white">
            <ICONS.Ticket />
          </div>
          <h1 className="text-xl font-semibold text-teams-purple tracking-tight">Support Tickets</h1>
        </div>
        <div className="flex items-center space-x-4">
          <div className="text-right hidden sm:block">
             <div className="text-sm font-semibold">{user.name}</div>
             <div className="text-xs text-gray-500 uppercase">{user.role}</div>
          </div>
          <button 
            onClick={handleLogout}
            className="text-gray-400 hover:text-teams-purple transition-colors p-1"
            title="Logout"
          >
            <ICONS.Logout />
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-4xl mx-auto p-6">

        {/* Navigation Tabs */}
        <div className="flex space-x-1 border-b border-gray-300 mb-6 overflow-x-auto">
          <button
            onClick={() => setActiveTab(Tab.LIST)}
            className={`px-4 py-2 text-sm font-medium transition-colors border-b-2 whitespace-nowrap ${
              activeTab === Tab.LIST 
                ? 'border-teams-purple text-teams-purple' 
                : 'border-transparent text-gray-500 hover:text-gray-700'
            }`}
          >
            Tickets
          </button>

          <button
            onClick={() => setActiveTab(Tab.NEW)}
            className={`px-4 py-2 text-sm font-medium transition-colors border-b-2 whitespace-nowrap ${
              activeTab === Tab.NEW 
                ? 'border-teams-purple text-teams-purple' 
                : 'border-transparent text-gray-500 hover:text-gray-700'
            }`}
          >
            New Ticket
          </button>

          <button
            onClick={() => setActiveTab(Tab.CHAT)}
            className={`px-4 py-2 text-sm font-medium transition-colors border-b-2 flex items-center space-x-1 whitespace-nowrap ${
              activeTab === Tab.CHAT
                ? 'border-teams-purple text-teams-purple' 
                : 'border-transparent text-gray-500 hover:text-gray-700'
            }`}
          >
             <ICONS.Sparkles />
             <span>AI Assistant</span>
          </button>

          {isAdmin && (
            <button
              onClick={() => setActiveTab(Tab.ADMIN)}
              className={`px-4 py-2 text-sm font-medium transition-colors border-b-2 flex items-center space-x-1 whitespace-nowrap ${
                activeTab === Tab.ADMIN
                  ? 'border-teams-purple text-teams-purple' 
                  : 'border-transparent text-gray-500 hover:text-gray-700'
              }`}
            >
              <ICONS.Shield />
              <span>Admin</span>
            </button>
          )}
        </div>

        {/* Tab Content */}
        <div className="transition-all duration-300 ease-in-out">
          {activeTab === Tab.LIST && (
            <>
              <div className="flex justify-between items-center mb-4">
                <h2 className="text-lg font-bold text-gray-700">
                  {user.role === UserRole.USER ? 'My Tickets' : 'Ticket Queue'}
                </h2>
                <button 
                   onClick={fetchTickets}
                   className="text-sm text-teams-purple hover:underline"
                >
                  Refresh
                </button>
              </div>
              <TicketList 
                tickets={tickets} 
                onStatusChange={handleStatusChange} 
                isLoading={isLoading} 
                currentUser={user}
              />
            </>
          )}

          {activeTab === Tab.NEW && (
            <TicketForm 
              onSubmit={handleCreateTicket} 
              onCancel={() => setActiveTab(Tab.LIST)} 
            />
          )}

          {activeTab === Tab.CHAT && (
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="md:col-span-2">
