import { AdminPanel } from './components/AdminPanel';
import { LoginScreen } from './components/LoginScreen';
import { NotificationPanel } from './components/NotificationPanel';
import { ticketService } from './services/ticketService';
import { notificationService } from './services/notificationService';
import { Ticket, TicketStatus, TicketType, User, UserRole, Notification } from './types';
import { ICONS, TEAMS_THEME_COLOR } from './constants';

enum Tab {
  LIST = 'list',
  NEW = 'new',
  CHAT = 'chat',
  ADMIN = 'admin'
}

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<Tab>(Tab.LIST);
  const [tickets, setTickets] = useState<Ticket[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  // Notification State
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [showNotifications, setShowNotifications] = useState(false);
  const [unreadCount, setUnreadCount] = useState(0);

  const fetchTickets = async () => {
    setIsLoading(true);
    try {
      const data = await ticketService.getTickets();
      setTickets(data);
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoading(false);
    }
  };

  const fetchNotifications = () => {
    if (!user) return;
    const data = notificationService.getNotifications(user.id);
    setNotifications(data);
    setUnreadCount(data.filter(n => !n.read).length);
  };

  useEffect(() => {
    if (user) {
      fetchTickets();
      fetchNotifications();

      // Poll for notifications every 10 seconds to simulate real-time
      const interval = setInterval(fetchNotifications, 10000);
      return () => clearInterval(interval);
    }
  }, [user]);

  const handleCreateTicket = async (data: { tipo: TicketType; descripcion: string }) => {
    if (!user) return;
    try {
      await ticketService.createTicket(data, user); // Pass user
      await fetchTickets();
      setActiveTab(Tab.LIST);
    } catch (e) {
      alert("Error al crear ticket");
    }
  };

  const handleStatusChange = async (id: number, status: TicketStatus) => {
    try {
      const updated = await ticketService.updateTicketStatus(id, status);
      if (updated) {
        setTickets(prev => prev.map(t => t.id === id ? updated : t));
        // If the technician is also the user (rare but possible), update notifications immediately
        fetchNotifications();
      }
    } catch (e) {
      alert("Error al actualizar estado");
    }
  };

  const handleLogout = () => {
    setUser(null);
    setActiveTab(Tab.LIST);
    setShowNotifications(false);
  };

  if (!user) {
    return <LoginScreen onLogin={setUser} />;
  }

  const isAdmin = user.role === UserRole.ADMIN;

  return (
    <div className="min-h-screen bg-teams-light text-teams-dark font-sans">
      {/* Header */}
      <header className="bg-white border-b border-gray-200 px-6 py-4 flex items-center justify-between shadow-sm sticky top-0 z-10">
        <div className="flex items-center space-x-3">
          <div className="bg-teams-purple p-1.5 rounded text-white">
            <ICONS.Ticket />
          </div>
          <h1 className="text-xl font-semibold text-teams-purple tracking-tight">Tickets de Soporte</h1>
        </div>

        <div className="flex items-center space-x-4">
          {/* Notification Bell */}
          <div className="relative">
            <button 
              onClick={() => setShowNotifications(!showNotifications)}
              className="p-1 text-gray-500 hover:text-teams-purple relative transition-colors focus:outline-none"
              title="Notificaciones"
            >
              <ICONS.Bell />
              {unreadCount > 0 && (
                <span className="absolute top-0 right-0 block h-2.5 w-2.5 rounded-full bg-red-500 ring-2 ring-white transform translate-x-1/4 -translate-y-1/4" />
              )}
            </button>

            {showNotifications && (
              <NotificationPanel 
                userId={user.id}
                notifications={notifications}
                onClose={() => setShowNotifications(false)}
                onUpdateNotifications={(updated) => {
                  setNotifications(updated);
                  setUnreadCount(updated.filter(n => !n.read).length);
                }}
              />
            )}
          </div>

          <div className="text-right hidden sm:block">
             <div className="text-sm font-semibold">{user.name}</div>
             <div className="text-xs text-gray-500 uppercase">{user.role}</div>
          </div>
          <button 
            onClick={handleLogout}
            className="text-gray-400 hover:text-teams-purple transition-colors p-1"
            title="Cerrar Sesión"
          >
            <ICONS.Logout />
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-4xl mx-auto p-6" onClick={() => { if(showNotifications) setShowNotifications(false) }}>

        {/* Navigation Tabs */}
        <div className="flex space-x-1 border-b border-gray-300 mb-6 overflow-x-auto">
          <button
            onClick={() => setActiveTab(Tab.LIST)}
            className={`px-4 py-2 text-sm font-medium transition-colors border-b-2 whitespace-nowrap ${
              activeTab === Tab.LIST 
                ? 'border-teams-purple text-teams-purple' 
                : 'border-transparent text-gray-500 hover:text-gray-700'
            }`}
          >
            Tickets
          </button>

          <button
            onClick={() => setActiveTab(Tab.NEW)}
            className={`px-4 py-2 text-sm font-medium transition-colors border-b-2 whitespace-nowrap ${
              activeTab === Tab.NEW 
                ? 'border-teams-purple text-teams-purple' 
                : 'border-transparent text-gray-500 hover:text-gray-700'
            }`}
          >
            Nuevo Ticket
          </button>

          <button
            onClick={() => setActiveTab(Tab.CHAT)}
            className={`px-4 py-2 text-sm font-medium transition-colors border-b-2 flex items-center space-x-1 whitespace-nowrap ${
              activeTab === Tab.CHAT
                ? 'border-teams-purple text-teams-purple' 
                : 'border-transparent text-gray-500 hover:text-gray-700'
            }`}
          >
             <ICONS.Sparkles />
             <span>Asistente IA</span>
          </button>

          {isAdmin && (
            <button
              onClick={() => setActiveTab(Tab.ADMIN)}
              className={`px-4 py-2 text-sm font-medium transition-colors border-b-2 flex items-center space-x-1 whitespace-nowrap ${
                activeTab === Tab.ADMIN
                  ? 'border-teams-purple text-teams-purple' 
                  : 'border-transparent text-gray-500 hover:text-gray-700'
              }`}
            >
              <ICONS.Shield />
              <span>Admin</span>
            </button>
          )}
        </div>

        {/* Tab Content */}
        <div className="transition-all duration-300 ease-in-out">
          {activeTab === Tab.LIST && (
            <>
              <div className="flex justify-between items-center mb-4">
                <h2 className="text-lg font-bold text-gray-700">
                  {user.role === UserRole.USER ? 'Mis Tickets' : 'Cola de Tickets'}
                </h2>
                <button 
                   onClick={fetchTickets}
                   className="text-sm text-teams-purple hover:underline"
                >
                  Actualizar
                </button>
              </div>
              <TicketList 
                tickets={tickets} 
                onStatusChange={handleStatusChange} 
                isLoading={isLoading} 
                currentUser={user}
              />
            </>
          )}

          {activeTab === Tab.NEW && (
            <TicketForm 
              onSubmit={handleCreateTicket} 
              onCancel={() => setActiveTab(Tab.LIST)} 
            />
          )}

          {activeTab === Tab.CHAT && (
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="md:col-span-2">
                 <ChatAssistant />
              </div>
              <div className="bg-white p-4 rounded-lg border border-gray-200 h-fit">
                <h3 className="font-semibold mb-2 text-sm">Sobre Soporte IA</h3>
                <p className="text-xs text-gray-500 mb-3">
                  Nuestro Asistente IA usa <strong>Gemini Pro</strong> para ayudar a diagnosticar problemas antes de enviar un ticket.
                </p>
                <ul className="text-xs text-gray-500 list-disc list-inside space-y-1">
                  <li>Haz preguntas técnicas</li>
                  <li>Soluciona errores de software</li>
                  <li>Info de políticas al instante</li>
                </ul>
              </div>
            </div>
          )}

          {activeTab === Tab.ADMIN && isAdmin && (
            <AdminPanel />
          )}
        </div>
      </main>
    </div>
  );
}

payload.text:
Para implementar notificaciones reales en Microsoft Teams (dejando de lado la simulación con `localStorage`), la mejor opción para este caso de uso es utilizar **Microsoft Graph API para enviar Notificaciones al Feed de Actividad**.

Es menos intrusivo que un Bot conversacional y se integra nativamente en la "Campanita" de Teams.

Aquí tienes los pasos técnicos y el código necesario para implementarlo.

### 🏗️ Arquitectura Requerida

1.  **Azure AD (Entra ID):** Necesitas registrar la aplicación para obtener `Client ID` y `Client Secret`.
2.  **Manifest.json:** Debes declarar que tu app envía notificaciones.
3.  **Backend (Node.js):** El servidor debe obtener un token de acceso y llamar a la API de Graph.

---

### Paso 1: Configuración en Azure Portal

1.  Ve a [portal.azure.com](https://portal.azure.com) > **App registrations**.
2.  Registra una nueva app.
3.  En **API Permissions**, agrega: `TeamsActivity.Send` y `User.Read.All`.
4.  Crea un **Client Secret** y guarda el valor.
5.  Copia el **Application (client) ID** y el **Directory (tenant) ID**.

---

### Paso 2: Actualizar `manifest.json`

Debes añadir la sección `activities` en tu archivo `manifest/manifest.json`. Esto define qué tipos de notificaciones envía tu app.

```json
{
  // ... resto del manifest
  "activities": {
    "activityTypes": [
      {
        "type": "ticketUpdate",
        "description": "Notificación cuando cambia el estado de un ticket",
        "templateText": "El estado de tu ticket #{ticketId} ha cambiado a {status}"
      }
    ]
  }
}
```

---

### Paso 3: Código del Backend (Node.js)

En tu archivo `backend/server.js`, necesitas una función que obtenga un token de servidor y envíe la notificación.

Necesitarás instalar `axios` y `qs` en tu backend:
`npm install axios qs`

Agrega esto a tu `server.js`:

```javascript
const axios = require('axios');
const qs = require('qs');

// Credenciales de Azure (Pon esto en tu .env)
const TENANT_ID = process.env.TENANT_ID;
const CLIENT_ID = process.env.CLIENT_ID;
const CLIENT_SECRET = process.env.CLIENT_SECRET;
const TEAMS_APP_ID = process.env.TEAMS_APP_ID; // ID del manifest

// 1. Obtener Token de Acceso (Client Credentials Flow)
async function getAccessToken() {
  const url = `https://login.microsoftonline.com/${TENANT_ID}/oauth2/v2.0/token`;
  const data = qs.stringify({
    client_id: CLIENT_ID,
    scope: 'https://graph.microsoft.com/.default',
    client_secret: CLIENT_SECRET,
    grant_type: 'client_credentials'
  });

  const response = await axios.post(url, data, { 
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' } 
  });
  return response.data.access_token;
}

// 2. Enviar Notificación vía Graph API
async function sendTeamsNotification(userId, ticketId, newStatus) {
  try {
    const token = await getAccessToken();

    // NOTA: 'userId' debe ser el GUID real de Azure AD del usuario, 
    // no el '999' de nuestra demo.
    const url = `https://graph.microsoft.com/v1.0/users/${userId}/teamwork/sendActivityNotification`;

    const body = {
      topic: {
        source: "entityUrl",
        value: `https://graph.microsoft.com/v1.0/appCatalogs/teamsApps/${TEAMS_APP_ID}`
      },
      activityType: "ticketUpdate", // Debe coincidir con el manifest
      previewText: {
        content: `Ticket #${ticketId} actualizado`
      },
      templateParameters: [
        { name: "ticketId", value: ticketId.toString() },
        { name: "status", value: newStatus }
      ]
    };

    await axios.post(url, body, {
      headers: { Authorization: `Bearer ${token}` }
    });
    console.log(`Notificación enviada a ${userId}`);

  } catch (error) {
    console.error("Error enviando notificación:", error.response?.data || error.message);
  }
}

// 3. Modificar tu endpoint PUT existente
app.put('/api/tickets/:id', async (req, res) => {
  const { estado } = req.body;
  const ticketId = req.params.id;

  // ... lógica SQL para actualizar ...

  db.run(sql, params, function(err) {
    if (!err) {
        // Obtener el ID del usuario dueño del ticket desde la DB
        db.get("SELECT userId FROM tickets WHERE id = ?", [ticketId], (err, row) => {
            if (row && row.userId) {
                // Enviar notificación real
                sendTeamsNotification(row.userId, ticketId, estado);
            }
        });
    }
    // ... responder al cliente ...
  });
});
```

### 💡 Consideración Crítica: El ID de Usuario

En nuestra demo actual (frontend), estamos usando IDs falsos (`'999'`, `'1'`, `'2'`).

Para que **Microsoft Graph** funcione, necesitas el `Object ID` (GUID) real del usuario en Azure Active Directory.

**¿Cómo conseguirlo?**
1.  **Frontend (SSO):** Debes implementar Single Sign-On (SSO) en el frontend usando `microsoftTeams.authentication.getAuthToken`.
2.  **Intercambio:** Envías ese token al backend.
3.  **Decodificación:** El backend valida el token y extrae el campo `oid` (Object ID).
4.  **Guardado:** Cuando creas el ticket (`POST /api/tickets`), guardas ese `oid` en la columna `userId` de SQLite.

### Resumen de Diferencias (Graph vs Bot)

| Característica | Microsoft Graph (Actividad) | Teams Bot (Chat) |
| :--- | :--- | :--- |
| **Ubicación** | Feed de Actividad (Campanita) | Chat directo (Pestaña Chat) |
| **Intrusión** | Baja (Sutil) | Alta (Interrumpe al usuario) |
| **Complejidad** | Media (Requiere Azure AD App) | Alta (Requiere Bot Framework Service) |
| **Interactividad** | Solo clic para abrir App | Puede incluir botones "Responder", "Cerrar" |
| **Costo** | Gratis (parte de M365) | Azure Bot Service puede tener costo |

**Recomendación:** Empieza con **Graph Activity Feed** (los pasos de arriba) ya que es más profesional para actualizaciones de estado y no requiere mantener un servicio de Bot corriendo separadamente.

