export enum TicketStatus {
  PENDING = 'Pendiente',
  IN_PROGRESS = 'En Progreso',
  RESOLVED = 'Resuelto'
}

export enum TicketType {
  GENERAL = 'Servicios Generales',
  IT = 'Informática'
}

export interface Ticket {
  id: number;
  userId: string; // ID of the user who created the ticket
  userName: string; // Name of the user
  tipo: TicketType;
  descripcion: string;
  estado: TicketStatus;
  fecha: string;
}

export interface TicketComment {
  id: string;
  ticketId: number;
  userId: string;
  userName: string;
  userRole: UserRole;
  text: string;
  timestamp: string;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

export enum UserRole {
  USER = 'Usuario',
  TECHNICIAN = 'Técnico',
  ADMIN = 'Administrador'
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  avatar?: string;
}

export interface Notification {
  id: string;
  userId: string; // Recipient
  ticketId: number;
  message: string;
  read: boolean;
  timestamp: number;
}

import { Ticket, TicketStatus, TicketType, User, TicketComment, UserRole } from '../types';
import { notificationService } from './notificationService';

// Mock storage keys
const STORAGE_KEY = 'teams_tickets_db';
const STORAGE_KEY_COMMENTS = 'teams_tickets_comments';

// Ensure mock tickets have owner IDs for the demo to work
// We assign most to '999' (the default "Employee User" ID from userService)
const DEFAULT_TICKETS: Ticket[] = [
  {
    id: 101,
    userId: '999',
    userName: 'Employee User',
    tipo: TicketType.IT,
    descripcion: "La impresora del segundo piso no conecta a la red wifi.",
    estado: TicketStatus.PENDING,
    fecha: new Date(Date.now() - 1000 * 60 * 60 * 2).toISOString() // 2 hours ago
  },
  {
    id: 102,
    userId: '999',
    userName: 'Employee User',
    tipo: TicketType.GENERAL,
    descripcion: "Solicitud de reemplazo de silla ergonómica en puesto 4B.",
    estado: TicketStatus.IN_PROGRESS,
    fecha: new Date(Date.now() - 1000 * 60 * 60 * 24).toISOString() // 1 day ago
  },
  {
    id: 103,
    userId: '999',
    userName: 'Employee User',
    tipo: TicketType.IT,
    descripcion: "Error al intentar acceder al VPN desde casa. Muestra error 403.",
    estado: TicketStatus.PENDING,
    fecha: new Date(Date.now() - 1000 * 60 * 30).toISOString() // 30 mins ago
  },
  {
    id: 104,
    userId: '1', // Admin
    userName: 'Admin User',
    tipo: TicketType.GENERAL,
    descripcion: "Aire acondicionado de la sala de juntas hace ruido extraño.",
    estado: TicketStatus.RESOLVED,
    fecha: new Date(Date.now() - 1000 * 60 * 60 * 48).toISOString() // 2 days ago
  },
  {
    id: 105,
    userId: '999',
    userName: 'Employee User',
    tipo: TicketType.IT,
    descripcion: "Actualización de licencia de Office 365 para el departamento de ventas.",
    estado: TicketStatus.IN_PROGRESS,
    fecha: new Date(Date.now() - 1000 * 60 * 60 * 5).toISOString() // 5 hours ago
  }
];

export const ticketService = {
  getTickets: async (): Promise<Ticket[]> => {
    // Simulate network delay
    await new Promise(resolve => setTimeout(resolve, 500));

    const stored = localStorage.getItem(STORAGE_KEY);
    let tickets: Ticket[] = [];

    if (stored) {
      try {
        tickets = JSON.parse(stored);
      } catch (e) {
        console.error("Failed to parse tickets", e);
      }
    }

    // If no tickets exist (first run or empty), populate with defaults
    if (tickets.length === 0) {
      tickets = DEFAULT_TICKETS;
      localStorage.setItem(STORAGE_KEY, JSON.stringify(tickets));
    }

    // Sort by date desc
    return tickets.sort((a: Ticket, b: Ticket) => 
      new Date(b.fecha).getTime() - new Date(a.fecha).getTime()
    );
  },

  createTicket: async (data: { tipo: TicketType; descripcion: string }, user: User): Promise<Ticket> => {
    await new Promise(resolve => setTimeout(resolve, 600));

    const stored = localStorage.getItem(STORAGE_KEY);
    const tickets: Ticket[] = stored ? JSON.parse(stored) : [];

    const newTicket: Ticket = {
      id: Date.now(),
      userId: user.id,
      userName: user.name,
      tipo: data.tipo,
      descripcion: data.descripcion,
      estado: TicketStatus.PENDING,
      fecha: new Date().toISOString()
    };

    tickets.push(newTicket);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(tickets));

    return newTicket;
  },

  updateTicketStatus: async (id: number, status: TicketStatus): Promise<Ticket | null> => {
    await new Promise(resolve => setTimeout(resolve, 400));

    const stored = localStorage.getItem(STORAGE_KEY);
    if (!stored) return null;

    const tickets: Ticket[] = JSON.parse(stored);
    const index = tickets.findIndex(t => t.id === id);

    if (index === -1) return null;

    const oldStatus = tickets[index].estado;
    tickets[index].estado = status;
    localStorage.setItem(STORAGE_KEY, JSON.stringify(tickets));

    // TRIGGER NOTIFICATION
    // If status changed, notify the owner of the ticket
    if (oldStatus !== status) {
        const ticketOwnerId = tickets[index].userId;
        const message = `El estado de tu ticket #${tickets[index].id} ha cambiado a: ${status}`;
        notificationService.addNotification(ticketOwnerId, tickets[index].id, message);
    }

    return tickets[index];
  },

  // COMMENTS SYSTEM

  getComments: async (ticketId: number): Promise<TicketComment[]> => {
    await new Promise(resolve => setTimeout(resolve, 300));
    const stored = localStorage.getItem(STORAGE_KEY_COMMENTS);
    if (!stored) return [];

    try {
      const allComments: TicketComment[] = JSON.parse(stored);
      return allComments.filter(c => c.ticketId === ticketId).sort((a,b) => 
        new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime()
      );
    } catch (e) {
      return [];
    }
  },

  addComment: async (ticketId: number, text: string, user: User): Promise<TicketComment> => {
    await new Promise(resolve => setTimeout(resolve, 300));

    const stored = localStorage.getItem(STORAGE_KEY_COMMENTS);
    const comments: TicketComment[] = stored ? JSON.parse(stored) : [];

    const newComment: TicketComment = {
      id: Date.now().toString(),
      ticketId,
      userId: user.id,
      userName: user.name,
      userRole: user.role,
      text,
      timestamp: new Date().toISOString()
    };

    comments.push(newComment);
    localStorage.setItem(STORAGE_KEY_COMMENTS, JSON.stringify(comments));

    // NOTIFICATION LOGIC FOR COMMENTS
    const tickets: Ticket[] = JSON.parse(localStorage.getItem(STORAGE_KEY) || '[]');
    const ticket = tickets.find(t => t.id === ticketId);

    if (ticket) {
        // If sender is NOT the owner, notify the owner
        if (user.id !== ticket.userId) {
             const msg = `Nuevo comentario de ${user.name} en ticket #${ticketId}: "${text.substring(0, 30)}${text.length > 30 ? '...' : ''}"`;
             notificationService.addNotification(ticket.userId, ticketId, msg);
        }

        // Note: In a real system we would also notify technicians if the USER comments, 
        // but since technicians are dynamic in this simple demo, we skip that complexity.
    }

    return newComment;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Ticket, TicketComment, User, TicketStatus, UserRole } from '../types';
import { ticketService } from '../services/ticketService';
import { ICONS } from '../constants';

interface TicketDetailProps {
  ticket: Ticket;
  currentUser: User;
  onClose: () => void;
  onStatusChange: (id: number, status: TicketStatus) => void;
}

const statusColors = {
  [TicketStatus.PENDING]: 'bg-red-100 text-red-800 border-red-200',
  [TicketStatus.IN_PROGRESS]: 'bg-yellow-100 text-yellow-800 border-yellow-200',
  [TicketStatus.RESOLVED]: 'bg-green-100 text-green-800 border-green-200',
};

export const TicketDetail: React.FC<TicketDetailProps> = ({ ticket, currentUser, onClose, onStatusChange }) => {
  const [comments, setComments] = useState<TicketComment[]>([]);
  const [newComment, setNewComment] = useState('');
  const [loadingComments, setLoadingComments] = useState(true);
  const [sending, setSending] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const canManage = currentUser.role === UserRole.TECHNICIAN || currentUser.role === UserRole.ADMIN;

  useEffect(() => {
    loadComments();
  }, [ticket.id]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [comments]);

  const loadComments = async () => {
    setLoadingComments(true);
    const data = await ticketService.getComments(ticket.id);
    setComments(data);
    setLoadingComments(false);
  };

  const handleSendComment = async () => {
    if (!newComment.trim()) return;
    setSending(true);
    try {
      const added = await ticketService.addComment(ticket.id, newComment, currentUser);
      setComments(prev => [...prev, added]);
      setNewComment('');
    } catch (e) {
      console.error(e);
    } finally {
      setSending(false);
    }
  };

  return (
    <div className="bg-white rounded-lg border border-gray-200 shadow-sm h-[calc(100vh-140px)] flex flex-col">
      {/* Header */}
      <div className="p-4 border-b border-gray-200 flex justify-between items-start bg-gray-50 rounded-t-lg">
        <div className="flex items-start gap-3">
          <button onClick={onClose} className="mt-1 text-gray-500 hover:text-teams-purple">
            <ICONS.ArrowLeft />
          </button>
          <div>
            <div className="flex items-center space-x-2 mb-1">
              <span className="text-sm font-mono text-gray-500">#{ticket.id}</span>
              <span className={`px-2 py-0.5 text-xs rounded-full border font-medium ${statusColors[ticket.estado]}`}>
                {ticket.estado}
              </span>
            </div>
            <h2 className="font-semibold text-gray-800">{ticket.descripcion}</h2>
            <div className="text-xs text-gray-500 mt-1">
              Creado por <strong>{ticket.userName}</strong> el {new Date(ticket.fecha).toLocaleString()}
            </div>
          </div>
        </div>

        {/* Actions */}
        {canManage && (
            <div className="flex space-x-2">
                {ticket.estado !== TicketStatus.RESOLVED && (
                    <button 
                        onClick={() => onStatusChange(ticket.id, TicketStatus.RESOLVED)}
                        className="text-xs bg-green-600 text-white px-3 py-1.5 rounded hover:bg-green-700"
                    >
                        Resolver Ticket
                    </button>
                )}
                {ticket.estado === TicketStatus.RESOLVED && (
                    <button 
                        onClick={() => onStatusChange(ticket.id, TicketStatus.IN_PROGRESS)}
                        className="text-xs bg-gray-200 text-gray-700 px-3 py-1.5 rounded hover:bg-gray-300"
                    >
                        Reabrir
                    </button>
                )}
            </div>
        )}
      </div>

      {/* Chat Area */}
      <div className="flex-1 overflow-y-auto p-4 bg-white space-y-4">
        {loadingComments ? (
          <div className="flex justify-center py-4 text-gray-400">
            <ICONS.Spinner />
          </div>
        ) : comments.length === 0 ? (
          <div className="text-center text-gray-400 text-sm py-8">
            No hay comentarios aún. Inicia la conversación.
          </div>
        ) : (
          comments.map(comment => {
            const isMe = comment.userId === currentUser.id;
            const isTech = comment.userRole === UserRole.TECHNICIAN || comment.userRole === UserRole.ADMIN;

            return (
              <div key={comment.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] rounded-lg p-3 text-sm border ${
                  isMe 
                    ? 'bg-blue-50 border-blue-100 text-blue-900 rounded-br-none' 
                    : isTech 
                        ? 'bg-orange-50 border-orange-100 text-orange-900 rounded-bl-none'
                        : 'bg-gray-100 border-gray-200 text-gray-800 rounded-bl-none'
                }`}>
                  <div className="flex justify-between items-baseline mb-1 gap-4">
                    <span className="font-semibold text-xs">
                        {comment.userName} {isTech && !isMe && '(Soporte)'}
                    </span>
                    <span className="text-[10px] opacity-60">
                        {new Date(comment.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                    </span>
                  </div>
                  <p>{comment.text}</p>
                </div>
              </div>
            );
          })
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-4 border-t border-gray-200 bg-gray-50 rounded-b-lg">
        <div className="flex gap-2">
          <input 
            type="text" 
            value={newComment}
            onChange={(e) => setNewComment(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSendComment()}
            placeholder="Escribe un mensaje o actualización..."
            className="flex-1 border border-gray-300 rounded-md px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-teams-purple"
          />
          <button 
            onClick={handleSendComment}
            disabled={sending || !newComment.trim()}
            className="bg-teams-purple text-white px-4 py-2 rounded-md hover:bg-opacity-90 disabled:opacity-50 text-sm font-medium"
          >
            {sending ? '...' : 'Enviar'}
          </button>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { Ticket, TicketStatus, User, UserRole } from '../types';
import { ICONS } from '../constants';

interface TicketListProps {
  tickets: Ticket[];
  onStatusChange: (id: number, status: TicketStatus) => void;
  onSelectTicket: (ticket: Ticket) => void;
  isLoading: boolean;
  currentUser: User;
}

const statusColors = {
  [TicketStatus.PENDING]: 'bg-red-100 text-red-800 border-red-200',
  [TicketStatus.IN_PROGRESS]: 'bg-yellow-100 text-yellow-800 border-yellow-200',
  [TicketStatus.RESOLVED]: 'bg-green-100 text-green-800 border-green-200',
};

export const TicketList: React.FC<TicketListProps> = ({ 
  tickets, 
  onStatusChange, 
  onSelectTicket, 
  isLoading, 
  currentUser 
}) => {
  const canManage = currentUser.role === UserRole.TECHNICIAN || currentUser.role === UserRole.ADMIN;

  if (isLoading) {
    return (
      <div className="flex justify-center items-center py-12">
        <div className="text-teams-purple animate-spin">
           <ICONS.Spinner />
        </div>
        <span className="ml-2 text-gray-500">Cargando tickets...</span>
      </div>
    );
  }

  if (tickets.length === 0) {
    return (
      <div className="text-center py-12 bg-white rounded-lg border border-gray-200">
        <p className="text-gray-500">No se encontraron tickets activos.</p>
        <p className="text-sm text-gray-400 mt-1">Crea un nuevo ticket para comenzar.</p>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {tickets.map((ticket) => (
        <div 
          key={ticket.id} 
          className="bg-white p-4 rounded-lg border border-gray-200 shadow-sm hover:shadow-md transition-shadow duration-200"
        >
          <div className="flex justify-between items-start">
            <div className="flex-1 cursor-pointer" onClick={() => onSelectTicket(ticket)}>
              <div className="flex items-center space-x-2 mb-1">
                <span className="text-xs font-mono text-gray-400">#{ticket.id}</span>
                <span className={`px-2 py-0.5 text-xs rounded-full border font-medium ${statusColors[ticket.estado]}`}>
                  {ticket.estado}
                </span>
                <span className="text-xs text-gray-400 bg-gray-100 px-2 py-0.5 rounded">
                  {ticket.tipo}
                </span>
              </div>
              <h3 className="text-gray-800 font-medium mt-1 hover:text-teams-purple transition-colors">
                {ticket.descripcion}
              </h3>
              <p className="text-xs text-gray-400 mt-2">
                {ticket.userName} · {new Date(ticket.fecha).toLocaleString()}
              </p>
            </div>

            <div className="flex flex-col space-y-2 ml-4 items-end">
               <button 
                  onClick={() => onSelectTicket(ticket)}
                  className="text-gray-400 hover:text-teams-purple p-1 flex items-center text-xs mb-1"
                  title="Ver conversación"
               >
                 <ICONS.MessageCircle />
                 <span className="ml-1">Ver</span>
               </button>

               {/* Only show status action buttons if user is Admin or Technician */}
               {canManage && (
                <>
                   {ticket.estado === TicketStatus.PENDING && (
                     <button
                       onClick={() => onStatusChange(ticket.id, TicketStatus.IN_PROGRESS)}
                       className="text-xs bg-teams-purple text-white px-3 py-1 rounded hover:bg-opacity-90 transition-colors whitespace-nowrap"
                     >
                       Comenzar
                     </button>
                   )}

                   {ticket.estado === TicketStatus.IN_PROGRESS && (
                     <button
                       onClick={() => onStatusChange(ticket.id, TicketStatus.RESOLVED)}
                       className="text-xs bg-green-600 text-white px-3 py-1 rounded hover:bg-green-700 transition-colors whitespace-nowrap"
                     >
                       Resolver
                     </button>
                   )}

                   {ticket.estado === TicketStatus.RESOLVED && (
                     <button
                       onClick={() => onStatusChange(ticket.id, TicketStatus.PENDING)}
                       className="text-xs text-gray-500 hover:text-gray-700 underline whitespace-nowrap"
                     >
                       Reabrir
                     </button>
                   )}
                </>
               )}
            </div>
          </div>
        </div>
      ))}
    </div>
  );
