export const ticketService = {
  getTickets: async (currentUserId?: string): Promise<Ticket[]> => {
    // Simulate network delay
    await new Promise(resolve => setTimeout(resolve, 500));

    const stored = localStorage.getItem(STORAGE_KEY);
    let tickets: Ticket[] = [];

    if (stored) {
      try {
        tickets = JSON.parse(stored);
      } catch (e) {
        console.error("Failed to parse tickets", e);
      }
    }

    if (tickets.length === 0) {
      tickets = DEFAULT_TICKETS;
      localStorage.setItem(STORAGE_KEY, JSON.stringify(tickets));
    }

    // CALCULATE UNREAD MESSAGES IF USER IS PROVIDED
    if (currentUserId) {
      const storedComments = localStorage.getItem(STORAGE_KEY_COMMENTS);
      const allComments: TicketComment[] = storedComments ? JSON.parse(storedComments) : [];

      const storedReads = localStorage.getItem(STORAGE_KEY_READS);
      const readReceipts: Record<string, number> = storedReads ? JSON.parse(storedReads) : {};

      tickets = tickets.map(ticket => {
        const ticketComments = allComments.filter(c => c.ticketId === ticket.id);

        if (ticketComments.length === 0) {
          return { ...ticket, unreadCount: 0, hasMessages: false };
        }

        const readKey = `${currentUserId}_${ticket.id}`;
        const lastReadTime = readReceipts[readKey] || 0;

        // Count comments that are NOT from me AND are newer than last read time
        const unreadCount = ticketComments.filter(c => 
          c.userId !== currentUserId && 
          new Date(c.timestamp).getTime() > lastReadTime
        ).length;

        return { 
          ...ticket, 
          unreadCount,
          hasMessages: true
        };
      });
    }

    // Sort by date desc
    return tickets.sort((a: Ticket, b: Ticket) => 
      new Date(b.fecha).getTime() - new Date(a.fecha).getTime()
    );
  },

  createTicket: async (data: { tipo: TicketType; descripcion: string }, user: User): Promise<Ticket> => {
    await new Promise(resolve => setTimeout(resolve, 600));

    const stored = localStorage.getItem(STORAGE_KEY);
    const tickets: Ticket[] = stored ? JSON.parse(stored) : [];

    const newTicket: Ticket = {
      id: Date.now(),
      userId: user.id,
      userName: user.name,
      tipo: data.tipo,
      descripcion: data.descripcion,
      estado: TicketStatus.PENDING,
      fecha: new Date().toISOString()
    };

    tickets.push(newTicket);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(tickets));

    // Auto-mark as read for creator
    ticketService.markAsRead(newTicket.id, user.id);

    return newTicket;
  },

  updateTicketStatus: async (id: number, status: TicketStatus): Promise<Ticket | null> => {
    await new Promise(resolve => setTimeout(resolve, 400));

    const stored = localStorage.getItem(STORAGE_KEY);
    if (!stored) return null;

    const tickets: Ticket[] = JSON.parse(stored);
    const index = tickets.findIndex(t => t.id === id);

    if (index === -1) return null;

    const oldStatus = tickets[index].estado;
    tickets[index].estado = status;
    localStorage.setItem(STORAGE_KEY, JSON.stringify(tickets));

    // Trigger Notification
    if (oldStatus !== status) {
        const ticketOwnerId = tickets[index].userId;
        const message = `El estado de tu ticket #${tickets[index].id} ha cambiado a: ${status}`;
        notificationService.addNotification(ticketOwnerId, tickets[index].id, message);
    }

    return tickets[index];
  },

  // COMMENTS SYSTEM

  getComments: async (ticketId: number): Promise<TicketComment[]> => {
    await new Promise(resolve => setTimeout(resolve, 300));
    const stored = localStorage.getItem(STORAGE_KEY_COMMENTS);
    if (!stored) return [];

    try {
      const allComments: TicketComment[] = JSON.parse(stored);
      return allComments.filter(c => c.ticketId === ticketId).sort((a,b) => 
        new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime()
      );
    } catch (e) {
      return [];
    }
  },

  addComment: async (ticketId: number, text: string, user: User): Promise<TicketComment> => {
    await new Promise(resolve => setTimeout(resolve, 300));

    const stored = localStorage.getItem(STORAGE_KEY_COMMENTS);
    const comments: TicketComment[] = stored ? JSON.parse(stored) : [];

    const newComment: TicketComment = {
      id: Date.now().toString(),
      ticketId,
      userId: user.id,
      userName: user.name,
      userRole: user.role,
      text,
      timestamp: new Date().toISOString()
    };

    comments.push(newComment);
    localStorage.setItem(STORAGE_KEY_COMMENTS, JSON.stringify(comments));

    // Automatically mark as read for the sender
    ticketService.markAsRead(ticketId, user.id);

    // Notification Logic
    const tickets: Ticket[] = JSON.parse(localStorage.getItem(STORAGE_KEY) || '[]');
    const ticket = tickets.find(t => t.id === ticketId);

    if (ticket) {
        if (user.id !== ticket.userId) {
             const msg = `Nuevo comentario de ${user.name} en ticket #${ticketId}`;
             notificationService.addNotification(ticket.userId, ticketId, msg);
        }
    }

    return newComment;
  },

  markAsRead: (ticketId: number, userId: string): void => {
    const storedReads = localStorage.getItem(STORAGE_KEY_READS);
    const readReceipts: Record<string, number> = storedReads ? JSON.parse(storedReads) : {};

    readReceipts[`${userId}_${ticketId}`] = Date.now();

    localStorage.setItem(STORAGE_KEY_READS, JSON.stringify(readReceipts));
  }
};

import React from 'react';
import { Ticket, TicketStatus, User, UserRole } from '../types';
import { ICONS } from '../constants';

interface TicketListProps {
  tickets: Ticket[];
  onStatusChange: (id: number, status: TicketStatus) => void;
  onSelectTicket: (ticket: Ticket) => void;
  isLoading: boolean;
  currentUser: User;
}

const statusColors = {
  [TicketStatus.PENDING]: 'bg-red-100 text-red-800 border-red-200',
  [TicketStatus.IN_PROGRESS]: 'bg-yellow-100 text-yellow-800 border-yellow-200',
  [TicketStatus.RESOLVED]: 'bg-green-100 text-green-800 border-green-200',
};

export const TicketList: React.FC<TicketListProps> = ({ 
  tickets, 
  onStatusChange, 
  onSelectTicket, 
  isLoading, 
  currentUser 
}) => {
  const canManage = currentUser.role === UserRole.TECHNICIAN || currentUser.role === UserRole.ADMIN;

  if (isLoading) {
    return (
      <div className="flex justify-center items-center py-12">
        <div className="text-teams-purple animate-spin">
           <ICONS.Spinner />
        </div>
        <span className="ml-2 text-gray-500">Cargando tickets...</span>
      </div>
    );
  }

  if (tickets.length === 0) {
    return (
      <div className="text-center py-12 bg-white rounded-lg border border-gray-200">
        <p className="text-gray-500">No se encontraron tickets activos.</p>
        <p className="text-sm text-gray-400 mt-1">Crea un nuevo ticket para comenzar.</p>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {tickets.map((ticket) => {
        const hasUnread = (ticket.unreadCount || 0) > 0;

        return (
          <div 
            key={ticket.id} 
            className={`bg-white p-4 rounded-lg border shadow-sm hover:shadow-md transition-shadow duration-200 ${hasUnread ? 'border-l-4 border-l-red-500' : 'border-gray-200'}`}
          >
            <div className="flex justify-between items-start">
              <div className="flex-1 cursor-pointer" onClick={() => onSelectTicket(ticket)}>
                <div className="flex items-center space-x-2 mb-1">
                  <span className="text-xs font-mono text-gray-400">#{ticket.id}</span>
                  <span className={`px-2 py-0.5 text-xs rounded-full border font-medium ${statusColors[ticket.estado]}`}>
                    {ticket.estado}
                  </span>
                  <span className="text-xs text-gray-400 bg-gray-100 px-2 py-0.5 rounded">
                    {ticket.tipo}
                  </span>

                  {/* Message Indicators */}
                  {hasUnread ? (
                    <span className="flex items-center space-x-1 bg-red-100 text-red-600 px-2 py-0.5 rounded-full text-xs font-bold animate-pulse">
                      <ICONS.MessageCircle />
                      <span>{ticket.unreadCount} nuevo{ticket.unreadCount !== 1 ? 's' : ''}</span>
                    </span>
                  ) : ticket.hasMessages ? (
                    <span className="text-gray-400" title="Hay comentarios">
                      <ICONS.MessageCircle />
                    </span>
                  ) : null}

                </div>
                <h3 className={`text-gray-800 font-medium mt-1 hover:text-teams-purple transition-colors ${hasUnread ? 'font-bold' : ''}`}>
                  {ticket.descripcion}
                </h3>
                <p className="text-xs text-gray-400 mt-2">
                  {ticket.userName} · {new Date(ticket.fecha).toLocaleString()}
                </p>
              </div>

              <div className="flex flex-col space-y-2 ml-4 items-end">
                 <button 
                    onClick={() => onSelectTicket(ticket)}
                    className={`p-1 flex items-center text-xs mb-1 ${hasUnread ? 'text-teams-purple font-semibold' : 'text-gray-400 hover:text-teams-purple'}`}
                    title="Ver conversación"
                 >
                   <ICONS.MessageCircle />
                   <span className="ml-1">Ver</span>
                 </button>

                 {/* Only show status action buttons if user is Admin or Technician */}
                 {canManage && (
                  <>
                     {ticket.estado === TicketStatus.PENDING && (
                       <button
                         onClick={() => onStatusChange(ticket.id, TicketStatus.IN_PROGRESS)}
                         className="text-xs bg-teams-purple text-white px-3 py-1 rounded hover:bg-opacity-90 transition-colors whitespace-nowrap"
                       >
                         Comenzar
                       </button>
                     )}

                     {ticket.estado === TicketStatus.IN_PROGRESS && (
                       <button
                         onClick={() => onStatusChange(ticket.id, TicketStatus.RESOLVED)}
                         className="text-xs bg-green-600 text-white px-3 py-1 rounded hover:bg-green-700 transition-colors whitespace-nowrap"
                       >
                         Resolver
                       </button>
                     )}

                     {ticket.estado === TicketStatus.RESOLVED && (
                       <button
                         onClick={() => onStatusChange(ticket.id, TicketStatus.PENDING)}
                         className="text-xs text-gray-500 hover:text-gray-700 underline whitespace-nowrap"
                       >
                         Reabrir
                       </button>
                     )}
                  </>
                 )}
              </div>
            </div>
          </div>
        );
      })}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { TicketList } from './components/TicketList';
import { TicketForm } from './components/TicketForm';
import { ChatAssistant } from './components/ChatAssistant';
import { AdminPanel } from './components/AdminPanel';
import { LoginScreen } from './components/LoginScreen';
import { NotificationPanel } from './components/NotificationPanel';
import { TicketDetail } from './components/TicketDetail';
import { ticketService } from './services/ticketService';
import { notificationService } from './services/notificationService';
import { Ticket, TicketStatus, TicketType, User, UserRole, Notification } from './types';
import { ICONS, TEAMS_THEME_COLOR } from './constants';

enum Tab {
  LIST = 'list',
  NEW = 'new',
  CHAT = 'chat',
  ADMIN = 'admin'
}

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<Tab>(Tab.LIST);
  const [tickets, setTickets] = useState<Ticket[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [selectedTicket, setSelectedTicket] = useState<Ticket | null>(null);

  // Notification State
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [showNotifications, setShowNotifications] = useState(false);
  const [unreadCount, setUnreadCount] = useState(0);

  const fetchTickets = async () => {
    setIsLoading(true);
    try {
      // Pass user ID to calculate unread status
      const data = await ticketService.getTickets(user?.id);
      setTickets(data);
      // Update selected ticket data if it's currently open
      if (selectedTicket) {
        const updated = data.find(t => t.id === selectedTicket.id);
        if (updated) setSelectedTicket(updated);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoading(false);
    }
  };

  const fetchNotifications = () => {
    if (!user) return;
    const data = notificationService.getNotifications(user.id);
    setNotifications(data);
    setUnreadCount(data.filter(n => !n.read).length);
  };

  useEffect(() => {
    if (user) {
      fetchTickets();
      fetchNotifications();

      // Poll for notifications every 10 seconds to simulate real-time
      const interval = setInterval(() => {
        fetchNotifications();
        // Also background refresh tickets to see status changes and new comments
        if (activeTab === Tab.LIST && user) {
             ticketService.getTickets(user.id).then(setTickets);
        }
      }, 10000);
      return () => clearInterval(interval);
    }
  }, [user, activeTab]);

  const handleCreateTicket = async (data: { tipo: TicketType; descripcion: string }) => {
    if (!user) return;
    try {
      await ticketService.createTicket(data, user); // Pass user
      await fetchTickets();
      setActiveTab(Tab.LIST);
    } catch (e) {
      alert("Error al crear ticket");
    }
  };

  const handleStatusChange = async (id: number, status: TicketStatus) => {
    try {
      const updated = await ticketService.updateTicketStatus(id, status);
      if (updated) {
        setTickets(prev => prev.map(t => t.id === id ? { ...t, estado: status } : t));
        if (selectedTicket && selectedTicket.id === id) {
          setSelectedTicket({ ...selectedTicket, estado: status });
        }
        fetchNotifications();
      }
    } catch (e) {
      alert("Error al actualizar estado");
    }
  };

  const handleLogout = () => {
    setUser(null);
    setActiveTab(Tab.LIST);
    setShowNotifications(false);
    setSelectedTicket(null);
  };

  const handleSelectTicket = (ticket: Ticket) => {
      setSelectedTicket(ticket);
      if (user) {
        // Mark as read immediately when opening
        ticketService.markAsRead(ticket.id, user.id);
        // Optimistically update UI to remove badge
        setTickets(prev => prev.map(t => 
            t.id === ticket.id ? { ...t, unreadCount: 0 } : t
        ));
      }
  };

  const handleNotificationClick = (notif: Notification) => {
      // Find the ticket and open it
      const ticket = tickets.find(t => t.id === notif.ticketId);
      if (ticket) {
          handleSelectTicket(ticket);
          setActiveTab(Tab.LIST); 
          setShowNotifications(false);
          // Mark notification as read
          const updated = notificationService.markAsRead(notif.id);
          setNotifications(updated);
          setUnreadCount(updated.filter(n => !n.read).length);
      }
  };

  if (!user) {
    return <LoginScreen onLogin={setUser} />;
  }

  const isAdmin = user.role === UserRole.ADMIN;

  return (
    <div className="min-h-screen bg-teams-light text-teams-dark font-sans">
      {/* Header */}
      <header className="bg-white border-b border-gray-200 px-6 py-4 flex items-center justify-between shadow-sm sticky top-0 z-10">
        <div className="flex items-center space-x-3">
          <div className="bg-teams-purple p-1.5 rounded text-white">
            <ICONS.Ticket />
          </div>
          <h1 className="text-xl font-semibold text-teams-purple tracking-tight">Tickets de Soporte</h1>
        </div>

        <div className="flex items-center space-x-4">
          {/* Notification Bell */}
          <div className="relative">
            <button 
              onClick={() => setShowNotifications(!showNotifications)}
              className="p-1 text-gray-500 hover:text-teams-purple relative transition-colors focus:outline-none"
              title="Notificaciones"
            >
              <ICONS.Bell />
              {unreadCount > 0 && (
                <span className="absolute top-0 right-0 block h-2.5 w-2.5 rounded-full bg-red-500 ring-2 ring-white transform translate-x-1/4 -translate-y-1/4" />
              )}
            </button>

            {showNotifications && (
              <div className="absolute right-0 top-12 z-50">
                 <NotificationPanel 
                    userId={user.id}
                    notifications={notifications}
                    onClose={() => setShowNotifications(false)}
                    onUpdateNotifications={(updated) => {
                      setNotifications(updated);
                      setUnreadCount(updated.filter(n => !n.read).length);
                    }}
                 />
                 {/* Overlay hack to capture clicks on notifications to navigate */}
                 {notifications.length > 0 && (
                     <div className="absolute top-10 left-0 w-full h-full pointer-events-none"></div>
                 )}
              </div>
            )}
          </div>

          <div className="text-right hidden sm:block">
             <div className="text-sm font-semibold">{user.name}</div>
             <div className="text-xs text-gray-500 uppercase">{user.role}</div>
          </div>
          <button 
            onClick={handleLogout}
            className="text-gray-400 hover:text-teams-purple transition-colors p-1"
            title="Cerrar Sesión"
          >
            <ICONS.Logout />
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-4xl mx-auto p-6" onClick={() => { if(showNotifications) setShowNotifications(false) }}>

        {/* Navigation Tabs - Hide when looking at a specific ticket details */}
        {!selectedTicket && (
            <div className="flex space-x-1 border-b border-gray-300 mb-6 overflow-x-auto">
            <button
                onClick={() => setActiveTab(Tab.LIST)}
                className={`px-4 py-2 text-sm font-medium transition-colors border-b-2 whitespace-nowrap ${
                activeTab === Tab.LIST 
                    ? 'border-teams-purple text-teams-purple' 
                    : 'border-transparent text-gray-500 hover:text-gray-700'
                }`}
            >
                Tickets
            </button>

            <button
                onClick={() => setActiveTab(Tab.NEW)}
                className={`px-4 py-2 text-sm font-medium transition-colors border-b-2 whitespace-nowrap ${
                activeTab === Tab.NEW 
                    ? 'border-teams-purple text-teams-purple' 
                    : 'border-transparent text-gray-500 hover:text-gray-700'
                }`}
            >
                Nuevo Ticket
            </button>

            <button
                onClick={() => setActiveTab(Tab.CHAT)}
                className={`px-4 py-2 text-sm font-medium transition-colors border-b-2 flex items-center space-x-1 whitespace-nowrap ${
                activeTab === Tab.CHAT
                    ? 'border-teams-purple text-teams-purple' 
                    : 'border-transparent text-gray-500 hover:text-gray-700'
                }`}
            >
                <ICONS.Sparkles />
                <span>Asistente IA</span>
            </button>

            {isAdmin && (
                <button
                onClick={() => setActiveTab(Tab.ADMIN)}
                className={`px-4 py-2 text-sm font-medium transition-colors border-b-2 flex items-center space-x-1 whitespace-nowrap ${
                    activeTab === Tab.ADMIN
                    ? 'border-teams-purple text-teams-purple' 
                    : 'border-transparent text-gray-500 hover:text-gray-700'
                }`}
                >
                <ICONS.Shield />
                <span>Admin</span>
                </button>
            )}
            </div>
        )}

        {/* Tab Content */}
        <div className="transition-all duration-300 ease-in-out">
          {selectedTicket ? (
            <TicketDetail 
              ticket={selectedTicket} 
              currentUser={user}
              onClose={() => setSelectedTicket(null)}
              onStatusChange={handleStatusChange}
            />
          ) : (
            <>
                {activeTab === Tab.LIST && (
                    <>
                    <div className="flex justify-between items-center mb-4">
                        <h2 className="text-lg font-bold text-gray-700">
                        {user.role === UserRole.USER ? 'Mis Tickets' : 'Cola de Tickets'}
                        </h2>
                        <button 
                        onClick={fetchTickets}
                        className="text-sm text-teams-purple hover:underline"
                        >
                        Actualizar
                        </button>
                    </div>
                    <TicketList 
                        tickets={tickets} 
                        onStatusChange={handleStatusChange} 
                        onSelectTicket={handleSelectTicket}
                        isLoading={isLoading} 
                        currentUser={user}
                    />
                    </>
                )}

                {activeTab === Tab.NEW && (
                    <TicketForm 
                    onSubmit={handleCreateTicket} 
                    onCancel={() => setActiveTab(Tab.LIST)} 
                    />
                )}

                {activeTab === Tab.CHAT && (
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    <div className="md:col-span-2">
                        <ChatAssistant />
                    </div>
                    <div className="bg-white p-4 rounded-lg border border-gray-200 h-fit">
                        <h3 className="font-semibold mb-2 text-sm">Sobre Soporte IA</h3>
                        <p className="text-xs text-gray-500 mb-3">
                        Nuestro Asistente IA usa <strong>Gemini Pro</strong> para ayudar a diagnosticar problemas antes de enviar un ticket.
                        </p>
                        <ul className="text-xs text-gray-500 list-disc list-inside space-y-1">
                        <li>Haz preguntas técnicas</li>
                        <li>Soluciona errores de software</li>
                        <li>Info de políticas al instante</li>
                        </ul>
                    </div>
                    </div>
                )}

                {activeTab === Tab.ADMIN && isAdmin && (
                    <AdminPanel />
                )}
            </>
          )}
        </div>
      </main>
    </div>
  );
}

