// Mock storage keys
const STORAGE_KEY = 'teams_tickets_db';
const STORAGE_KEY_COMMENTS = 'teams_tickets_comments';
const STORAGE_KEY_READS = 'teams_tickets_reads'; // Format: { "userId_ticketId": timestamp }

