  userName: string; // Name of the user
  tipo: TicketType;
  descripcion: string;
  estado: TicketStatus;
  fecha: string;
  unreadCount?: number; // Calculated property for UI
  hasMessages?: boolean; // Calculated property for UI
  messageCount?: number; // Total messages count
}

