  TECHNICIAN = 'Técnico',
  ADMIN = 'Administrador'
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  avatar?: string;
}

export interface Notification {
  id: string;
  userId: string; // Recipient
  ticketId: number;
  message: string;
  read: boolean;
  timestamp: number;
}

