export const ticketService = {
  getTickets: async (currentUserId?: string): Promise<Ticket[]> => {
    // Simulate network delay
    await new Promise(resolve => setTimeout(resolve, 500));

    const stored = localStorage.getItem(STORAGE_KEY);
    let tickets: Ticket[] = [];

    if (stored) {
      try {
        tickets = JSON.parse(stored);
      } catch (e) {
        console.error("Failed to parse tickets", e);
      }
    }

    if (tickets.length === 0) {
      tickets = DEFAULT_TICKETS;
      localStorage.setItem(STORAGE_KEY, JSON.stringify(tickets));
    }

    // CALCULATE UNREAD MESSAGES IF USER IS PROVIDED
    if (currentUserId) {
      const storedComments = localStorage.getItem(STORAGE_KEY_COMMENTS);
      const allComments: TicketComment[] = storedComments ? JSON.parse(storedComments) : [];

      const storedReads = localStorage.getItem(STORAGE_KEY_READS);
      const readReceipts: Record<string, number> = storedReads ? JSON.parse(storedReads) : {};

      tickets = tickets.map(ticket => {
        const ticketComments = allComments.filter(c => c.ticketId === ticket.id);
        const messageCount = ticketComments.length;

        if (ticketComments.length === 0) {
          return { ...ticket, unreadCount: 0, hasMessages: false, messageCount: 0 };
        }

        const readKey = `${currentUserId}_${ticket.id}`;
        const lastReadTime = readReceipts[readKey] || 0;

        // Count comments that are NOT from me AND are newer than last read time
        const unreadCount = ticketComments.filter(c => 
          c.userId !== currentUserId && 
          new Date(c.timestamp).getTime() > lastReadTime
        ).length;

        return { 
          ...ticket, 
          unreadCount,
          hasMessages: true,
          messageCount
        };
      });
    }

    // Sort by date desc
    return tickets.sort((a: Ticket, b: Ticket) => 
      new Date(b.fecha).getTime() - new Date(a.fecha).getTime()
    );
  },

  /**
   * Helper specifically for AI to get context of ALL resolved/closed tickets
   * to learn from past solutions.
   */
  getResolvedTicketsForAI: async (): Promise<string> => {
    const stored = localStorage.getItem(STORAGE_KEY);
    const tickets: Ticket[] = stored ? JSON.parse(stored) : DEFAULT_TICKETS;

    const resolved = tickets.filter(t => t.estado === TicketStatus.RESOLVED);

    const storedComments = localStorage.getItem(STORAGE_KEY_COMMENTS);
    const allComments: TicketComment[] = storedComments ? JSON.parse(storedComments) : [];

    // Format for AI consumption
    return resolved.map(t => {
      const ticketComments = allComments.filter(c => c.ticketId === t.id);
      const commentsText = ticketComments.map(c => `[${c.userRole}]: ${c.text}`).join('; ');
      return `Ticket #${t.id} (${t.tipo}): ${t.descripcion}. Historial: ${commentsText}`;
    }).join('\n\n');
  },

  createTicket: async (data: { tipo: TicketType; descripcion: string }, user: User): Promise<Ticket> => {
    await new Promise(resolve => setTimeout(resolve, 600));

    const stored = localStorage.getItem(STORAGE_KEY);
    const tickets: Ticket[] = stored ? JSON.parse(stored) : [];

    const newTicket: Ticket = {
      id: Date.now(),
      userId: user.id,
      userName: user.name,
      tipo: data.tipo,
      descripcion: data.descripcion,
      estado: TicketStatus.PENDING,
      fecha: new Date().toISOString()
    };

    tickets.push(newTicket);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(tickets));

    // Auto-mark as read for creator
    ticketService.markAsRead(newTicket.id, user.id);

    return newTicket;
  },

  updateTicketStatus: async (id: number, status: TicketStatus): Promise<Ticket | null> => {
    await new Promise(resolve => setTimeout(resolve, 400));

    const stored = localStorage.getItem(STORAGE_KEY);
    if (!stored) return null;

    const tickets: Ticket[] = JSON.parse(stored);
    const index = tickets.findIndex(t => t.id === id);

    if (index === -1) return null;

    const oldStatus = tickets[index].estado;
    tickets[index].estado = status;
    localStorage.setItem(STORAGE_KEY, JSON.stringify(tickets));

    // Trigger Notification
    if (oldStatus !== status) {
        const ticketOwnerId = tickets[index].userId;
        const message = `El estado de tu ticket #${tickets[index].id} ha cambiado a: ${status}`;
        notificationService.addNotification(ticketOwnerId, tickets[index].id, message);
    }

    return tickets[index];
  },

  // COMMENTS SYSTEM

  getComments: async (ticketId: number): Promise<TicketComment[]> => {
    await new Promise(resolve => setTimeout(resolve, 300));
    const stored = localStorage.getItem(STORAGE_KEY_COMMENTS);
    if (!stored) return [];

    try {
      const allComments: TicketComment[] = JSON.parse(stored);
      return allComments.filter(c => c.ticketId === ticketId).sort((a,b) => 
        new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime()
      );
    } catch (e) {
      return [];
    }
  },

  addComment: async (ticketId: number, text: string, user: User): Promise<TicketComment> => {
    await new Promise(resolve => setTimeout(resolve, 300));

    const stored = localStorage.getItem(STORAGE_KEY_COMMENTS);
    const comments: TicketComment[] = stored ? JSON.parse(stored) : [];

    const newComment: TicketComment = {
      id: Date.now().toString(),
      ticketId,
      userId: user.id,
      userName: user.name,
      userRole: user.role,
      text,
      timestamp: new Date().toISOString()
    };

    comments.push(newComment);
    localStorage.setItem(STORAGE_KEY_COMMENTS, JSON.stringify(comments));

    // Automatically mark as read for the sender
    ticketService.markAsRead(ticketId, user.id);

    // Notification Logic
    const tickets: Ticket[] = JSON.parse(localStorage.getItem(STORAGE_KEY) || '[]');
    const ticket = tickets.find(t => t.id === ticketId);

    if (ticket) {
        if (user.id !== ticket.userId) {
             const msg = `Nuevo comentario de ${user.name} en ticket #${ticketId}`;
             notificationService.addNotification(ticket.userId, ticketId, msg);
        }
    }

    return newComment;
  },

  markAsRead: (ticketId: number, userId: string): void => {
    const storedReads = localStorage.getItem(STORAGE_KEY_READS);
    const readReceipts: Record<string, number> = storedReads ? JSON.parse(storedReads) : {};

    readReceipts[`${userId}_${ticketId}`] = Date.now();

    localStorage.setItem(STORAGE_KEY_READS, JSON.stringify(readReceipts));
  }
};

import { GoogleGenAI } from "@google/genai";

// The API key must be obtained exclusively from the environment variable process.env.API_KEY.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const geminiService = {
  /**
   * Fast analysis of ticket content to suggest category or quick fixes
   * Uses Gemini Flash Lite for low latency
   */
  analyzeTicket: async (description: string): Promise<string> => {
    if (!description || description.length < 5) return "";

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-flash-lite-latest',
        contents: `Analiza esta descripción de ticket de soporte y proporciona una sugerencia de causa o categoría muy corta, de 1 oración. Responde en español.

        Descripción: ${description}`,
      });
      return response.text || "";
    } catch (error) {
      console.error("Gemini analysis failed:", error);
      return "";
    }
  },

  /**
   * Complex reasoning for the support assistant chat
   * Uses Gemini Pro
   * Now accepts a contextKnowledge parameter to "learn" from existing data
   */
  chatWithSupport: async (message: string, history: any[] = [], contextKnowledge: string = ""): Promise<string> => {
    try {
      const systemInstruction = `Eres un Asistente de Soporte IT experto y útil para una empresa.
      Tu objetivo es ayudar a los usuarios a resolver problemas técnicos o guiarlos.

      TIENES ACCESO A LA SIGUIENTE BASE DE CONOCIMIENTO Y TICKETS PREVIOS:
      ${contextKnowledge}

      INSTRUCCIONES:
      1. Si la pregunta del usuario se parece a un ticket resuelto anterior o a una FAQ de la base de conocimiento, USA esa información para dar la solución.
      2. Si encuentras una coincidencia, menciona "Según nuestra base de conocimientos..." o "Hemos tenido un caso similar..."
      3. Sé conciso y profesional.
      4. Responde siempre en español.
      `;

      const chat = ai.chats.create({
        model: 'gemini-3-pro-preview',
        history: history,
        config: {
          systemInstruction: systemInstruction,
        },
      });

      const result = await chat.sendMessage({ message });
      return result.text || "Tengo problemas para conectar con el cerebro de soporte en este momento.";
    } catch (error) {
      console.error("Gemini chat failed:", error);
      return "Lo siento, encontré un error al procesar tu solicitud.";
    }
  },

  /**
   * Vision capabilities to analyze screenshots of errors
   * Uses Gemini Pro Vision
   */
  analyzeScreenshot: async (base64Image: string): Promise<string> => {
    try {
      // Extract mime type if present, default to png
      const match = base64Image.match(/^data:(image\/[a-zA-Z+]+);base64,/);
      const mimeType = match ? match[1] : 'image/png';

      // Remove data URL prefix
      const cleanBase64 = base64Image.replace(/^data:image\/[a-zA-Z+]+;base64,/, '');

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: {
          parts: [
            {
              inlineData: {
                mimeType: mimeType,
                data: cleanBase64
              }
            },
            {
              text: "Analiza esta captura de pantalla. Si contiene un mensaje de error, extráelo. Describe el problema técnico visto en la imagen adecuado para una descripción de ticket de soporte IT. Responde en español."
            }
          ]
        }
      });
      return response.text || "";
    } catch (error) {
      console.error("Gemini vision failed:", error);
      throw error;
    }
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { geminiService } from '../services/geminiService';
import { ticketService } from '../services/ticketService';
import { wikiService } from '../services/wikiService';
import { ICONS } from '../constants';
import { ChatMessage } from '../types';

export const ChatAssistant: React.FC = () => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: '1',
      role: 'model',
      text: '¡Hola! Soy el Asistente IA de Soporte. Tengo acceso a las incidencias pasadas y a la Wiki. ¿En qué puedo ayudarte?',
      timestamp: Date.now()
    }
  ]);
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    try {
      // 1. Gather Context (FAQs + Past Resolved Tickets)
      const faqs = wikiService.getFaqsAsString();
      const resolvedTickets = await ticketService.getResolvedTicketsForAI();

      const combinedKnowledge = `
      --- PREGUNTAS FRECUENTES (Wiki Tech) ---
      ${faqs}

      --- HISTORIAL DE TICKETS RESUELTOS ---
      ${resolvedTickets}
      `;

      // 2. Send to Gemini with context
      // Note: We are passing empty history array for simplicity in this demo, 
      // but in a real app we'd map 'messages' state to Gemini history format.
      const responseText = await geminiService.chatWithSupport(userMsg.text, [], combinedKnowledge);

      const aiMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText,
        timestamp: Date.now()
      };

      setMessages(prev => [...prev, aiMsg]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="flex flex-col h-[500px] bg-white rounded-lg border border-gray-200 shadow-sm">
      <div className="p-4 border-b border-gray-100 bg-gray-50 rounded-t-lg flex items-center">
        <div className="text-teams-purple mr-2"><ICONS.Sparkles /></div>
        <h3 className="font-semibold text-gray-700">Asistente IA</h3>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div 
              className={`max-w-[80%] rounded-lg p-3 text-sm ${
                msg.role === 'user' 
                  ? 'bg-teams-purple text-white rounded-br-none' 
                  : 'bg-gray-100 text-gray-800 rounded-bl-none'
              }`}
            >
              {msg.text}
            </div>
          </div>
        ))}
        {isTyping && (
           <div className="flex justify-start">
             <div className="bg-gray-100 rounded-lg rounded-bl-none p-3 flex items-center space-x-1">
               <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"></div>
               <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-100"></div>
               <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-200"></div>
             </div>
           </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-3 border-t border-gray-100">
        <div className="flex space-x-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Escribe tu problema..."
            className="flex-1 border border-gray-300 rounded-md px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-teams-purple bg-white text-gray-900 placeholder-gray-500"
          />
          <button
            onClick={handleSend}
            disabled={isTyping || !input.trim()}
            className="bg-teams-purple text-white p-2 rounded-md hover:bg-opacity-90 disabled:opacity-50"
          >
            <ICONS.Chat />
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ICONS } from '../constants';
import { wikiService } from '../services/wikiService';
import { FAQ } from '../types';

export const WikiPanel: React.FC = () => {
  const [faqs, setFaqs] = useState<FAQ[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [openId, setOpenId] = useState<string | null>(null);

  useEffect(() => {
    setFaqs(wikiService.getFaqs());
  }, []);

  const filteredFaqs = faqs.filter(faq => 
    faq.question.toLowerCase().includes(searchTerm.toLowerCase()) || 
    faq.answer.toLowerCase().includes(searchTerm.toLowerCase()) ||
    faq.category.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const toggleAccordion = (id: string) => {
    setOpenId(openId === id ? null : id);
  };

  return (
    <div className="space-y-6">
      {/* Header & Search */}
      <div className="bg-white p-6 rounded-lg border border-gray-200 shadow-sm">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-6">
          <div>
            <h2 className="text-lg font-semibold text-teams-dark flex items-center">
              <span className="mr-2 text-teams-purple"><ICONS.Book /></span>
              Wiki Tech & FAQ
            </h2>
            <p className="text-sm text-gray-500">
              Base de conocimiento técnico y preguntas frecuentes para resolver problemas comunes.
            </p>
          </div>

          <div className="relative w-full md:w-64">
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
              <ICONS.Search />
            </div>
            <input
              type="text"
              placeholder="Buscar..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="pl-10 w-full border border-gray-300 rounded-md px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-teams-purple bg-white text-gray-900"
            />
          </div>
        </div>

        {/* Categories / List */}
        <div className="space-y-3">
          {filteredFaqs.length === 0 ? (
            <div className="text-center py-8 text-gray-400">
              No se encontraron resultados para "{searchTerm}"
            </div>
          ) : (
            filteredFaqs.map(faq => (
              <div key={faq.id} className="border border-gray-200 rounded-lg overflow-hidden bg-white">
                <button
                  onClick={() => toggleAccordion(faq.id)}
                  className={`w-full flex items-center justify-between p-4 text-left transition-colors ${openId === faq.id ? 'bg-gray-50' : 'hover:bg-gray-50'}`}
                >
                  <div className="flex items-center gap-3">
                    <span className="text-xs font-semibold px-2 py-1 rounded bg-blue-50 text-blue-700 border border-blue-100 uppercase tracking-wide">
                      {faq.category}
                    </span>
                    <span className="font-medium text-gray-800">{faq.question}</span>
                  </div>
                  <div className={`transform transition-transform duration-200 text-gray-400 ${openId === faq.id ? 'rotate-180' : ''}`}>
                    <ICONS.ChevronDown />
                  </div>
                </button>

                {openId === faq.id && (
                  <div className="p-4 pt-0 text-sm text-gray-600 bg-gray-50 border-t border-gray-100">
                    <div className="pt-3 leading-relaxed whitespace-pre-line">
                      {faq.answer}
                    </div>
                  </div>
                )}
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { TicketList } from './components/TicketList';
import { KanbanBoard } from './components/KanbanBoard';
import { TicketForm } from './components/TicketForm';
import { ChatAssistant } from './components/ChatAssistant';
import { AdminPanel } from './components/AdminPanel';
import { WikiPanel } from './components/WikiPanel';
import { LoginScreen } from './components/LoginScreen';
import { NotificationPanel } from './components/NotificationPanel';
import { TicketDetail } from './components/TicketDetail';
import { ticketService } from './services/ticketService';
import { notificationService } from './services/notificationService';
import { Ticket, TicketStatus, TicketType, User, UserRole, Notification } from './types';
import { ICONS, TEAMS_THEME_COLOR } from './constants';

enum Tab {
  LIST = 'list',
  NEW = 'new',
  CHAT = 'chat',
  WIKI = 'wiki',
  ADMIN = 'admin'
}

type ViewMode = 'list' | 'kanban';

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<Tab>(Tab.LIST);
  const [viewMode, setViewMode] = useState<ViewMode>('list');
  const [tickets, setTickets] = useState<Ticket[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [selectedTicket, setSelectedTicket] = useState<Ticket | null>(null);

  // Notification State
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [showNotifications, setShowNotifications] = useState(false);
  const [unreadCount, setUnreadCount] = useState(0);

  const fetchTickets = async () => {
    setIsLoading(true);
    try {
      // Pass user ID to calculate unread status
      const data = await ticketService.getTickets(user?.id);
      setTickets(data);
      // Update selected ticket data if it's currently open
      if (selectedTicket) {
        const updated = data.find(t => t.id === selectedTicket.id);
        if (updated) setSelectedTicket(updated);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoading(false);
    }
  };

  const fetchNotifications = () => {
    if (!user) return;
    const data = notificationService.getNotifications(user.id);
    setNotifications(data);
    setUnreadCount(data.filter(n => !n.read).length);
  };

  useEffect(() => {
    if (user) {
      fetchTickets();
      fetchNotifications();

      // Poll for notifications every 10 seconds to simulate real-time
      const interval = setInterval(() => {
        fetchNotifications();
        // Also background refresh tickets to see status changes and new comments
        if (activeTab === Tab.LIST && user) {
             ticketService.getTickets(user.id).then(setTickets);
        }
      }, 10000);
      return () => clearInterval(interval);
    }
  }, [user, activeTab]);

  const handleCreateTicket = async (data: { tipo: TicketType; descripcion: string }) => {
    if (!user) return;
    try {
      await ticketService.createTicket(data, user); // Pass user
      await fetchTickets();
      setActiveTab(Tab.LIST);
    } catch (e) {
      alert("Error al crear ticket");
    }
  };

  const handleStatusChange = async (id: number, status: TicketStatus) => {
    try {
      const updated = await ticketService.updateTicketStatus(id, status);
      if (updated) {
        setTickets(prev => prev.map(t => t.id === id ? { ...t, estado: status } : t));
        if (selectedTicket && selectedTicket.id === id) {
          setSelectedTicket({ ...selectedTicket, estado: status });
        }
        fetchNotifications();
      }
    } catch (e) {
      alert("Error al actualizar estado");
    }
  };

  const handleLogout = () => {
    setUser(null);
    setActiveTab(Tab.LIST);
    setViewMode('list');
    setShowNotifications(false);
    setSelectedTicket(null);
  };

  const handleSelectTicket = (ticket: Ticket) => {
      setSelectedTicket(ticket);
      if (user) {
        // Mark as read immediately when opening
        ticketService.markAsRead(ticket.id, user.id);
        // Optimistically update UI to remove badge
        setTickets(prev => prev.map(t => 
            t.id === ticket.id ? { ...t, unreadCount: 0 } : t
        ));
      }
  };

  const handleNotificationClick = (notif: Notification) => {
      // Find the ticket and open it
      const ticket = tickets.find(t => t.id === notif.ticketId);
      if (ticket) {
          handleSelectTicket(ticket);
          setActiveTab(Tab.LIST); 
          setShowNotifications(false);
          // Mark notification as read
          const updated = notificationService.markAsRead(notif.id);
          setNotifications(updated);
          setUnreadCount(updated.filter(n => !n.read).length);
      }
  };

  if (!user) {
    return <LoginScreen onLogin={setUser} />;
  }

  const isAdmin = user.role === UserRole.ADMIN;
  const isTechOrAdmin = user.role === UserRole.TECHNICIAN || user.role === UserRole.ADMIN;

  return (
    <div className="min-h-screen bg-teams-light text-teams-dark font-sans">
      {/* Header */}
      <header className="bg-white border-b border-gray-200 px-6 py-4 flex items-center justify-between shadow-sm sticky top-0 z-10">
        <div className="flex items-center space-x-3">
          <div className="bg-teams-purple p-1.5 rounded text-white">
            <ICONS.Ticket />
          </div>
          <h1 className="text-xl font-semibold text-teams-purple tracking-tight">Tickets de Soporte</h1>
        </div>

        <div className="flex items-center space-x-4">
          {/* Notification Bell */}
          <div className="relative">
            <button 
              onClick={() => setShowNotifications(!showNotifications)}
              className="p-1 text-gray-500 hover:text-teams-purple relative transition-colors focus:outline-none"
              title="Notificaciones"
            >
              <ICONS.Bell />
              {unreadCount > 0 && (
                <span className="absolute top-0 right-0 block h-2.5 w-2.5 rounded-full bg-red-500 ring-2 ring-white transform translate-x-1/4 -translate-y-1/4" />
              )}
            </button>

            {showNotifications && (
              <div className="absolute right-0 top-12 z-50">
                 <NotificationPanel 
                    userId={user.id}
                    notifications={notifications}
                    onClose={() => setShowNotifications(false)}
                    onUpdateNotifications={(updated) => {
                      setNotifications(updated);
                      setUnreadCount(updated.filter(n => !n.read).length);
                    }}
                 />
                 {/* Overlay hack to capture clicks on notifications to navigate */}
                 {notifications.length > 0 && (
                     <div className="absolute top-10 left-0 w-full h-full pointer-events-none"></div>
                 )}
              </div>
            )}
          </div>

          <div className="text-right hidden sm:block">
             <div className="text-sm font-semibold">{user.name}</div>
             <div className="text-xs text-gray-500 uppercase">{user.role}</div>
          </div>
          <button 
            onClick={handleLogout}
            className="text-gray-400 hover:text-teams-purple transition-colors p-1"
            title="Cerrar Sesión"
          >
            <ICONS.Logout />
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="w-full max-w-7xl mx-auto p-6" onClick={() => { if(showNotifications) setShowNotifications(false) }}>

        {/* Navigation Tabs - Hide when looking at a specific ticket details */}
        {!selectedTicket && (
            <div className="flex space-x-1 border-b border-gray-300 mb-6 overflow-x-auto">
            <button
                onClick={() => setActiveTab(Tab.LIST)}
                className={`px-4 py-2 text-sm font-medium transition-colors border-b-2 whitespace-nowrap ${
                activeTab === Tab.LIST 
                    ? 'border-teams-purple text-teams-purple' 
                    : 'border-transparent text-gray-500 hover:text-gray-700'
                }`}
            >
                Tickets
            </button>

            <button
                onClick={() => setActiveTab(Tab.NEW)}
                className={`px-4 py-2 text-sm font-medium transition-colors border-b-2 whitespace-nowrap ${
                activeTab === Tab.NEW 
                    ? 'border-teams-purple text-teams-purple' 
                    : 'border-transparent text-gray-500 hover:text-gray-700'
                }`}
            >
                Nuevo Ticket
            </button>

            <button
                onClick={() => setActiveTab(Tab.CHAT)}
                className={`px-4 py-2 text-sm font-medium transition-colors border-b-2 flex items-center space-x-1 whitespace-nowrap ${
                activeTab === Tab.CHAT
                    ? 'border-teams-purple text-teams-purple' 
                    : 'border-transparent text-gray-500 hover:text-gray-700'
                }`}
            >
                <ICONS.Sparkles />
                <span>Asistente IA</span>
            </button>

            <button
                onClick={() => setActiveTab(Tab.WIKI)}
                className={`px-4 py-2 text-sm font-medium transition-colors border-b-2 flex items-center space-x-1 whitespace-nowrap ${
                activeTab === Tab.WIKI
                    ? 'border-teams-purple text-teams-purple' 
                    : 'border-transparent text-gray-500 hover:text-gray-700'
                }`}
            >
                <ICONS.Book />
                <span>Wiki Tech</span>
            </button>

            {isAdmin && (
                <button
                onClick={() => setActiveTab(Tab.ADMIN)}
                className={`px-4 py-2 text-sm font-medium transition-colors border-b-2 flex items-center space-x-1 whitespace-nowrap ${
                    activeTab === Tab.ADMIN
                    ? 'border-teams-purple text-teams-purple' 
                    : 'border-transparent text-gray-500 hover:text-gray-700'
                }`}
                >
                <ICONS.Shield />
                <span>Admin</span>
                </button>
            )}
            </div>
        )}

        {/* Tab Content */}
        <div className="transition-all duration-300 ease-in-out">
          {selectedTicket ? (
            <TicketDetail 
              ticket={selectedTicket} 
              currentUser={user}
              onClose={() => setSelectedTicket(null)}
              onStatusChange={handleStatusChange}
            />
          ) : (
            <>
                {activeTab === Tab.LIST && (
                    <>
                    <div className="flex justify-between items-center mb-4">
                        <h2 className="text-lg font-bold text-gray-700">
                        {user.role === UserRole.USER ? 'Mis Tickets' : 'Cola de Tickets'}
                        </h2>

                        <div className="flex items-center space-x-4">
                            {isTechOrAdmin && (
                                <div className="flex bg-gray-100 p-1 rounded-md">
                                    <button 
                                        onClick={() => setViewMode('list')}
                                        className={`p-1.5 rounded transition-colors ${viewMode === 'list' ? 'bg-white shadow-sm text-teams-purple' : 'text-gray-500 hover:text-gray-700'}`}
                                        title="Vista de Lista"
                                    >
                                        <ICONS.List />
                                    </button>
                                    <button 
                                        onClick={() => setViewMode('kanban')}
                                        className={`p-1.5 rounded transition-colors ${viewMode === 'kanban' ? 'bg-white shadow-sm text-teams-purple' : 'text-gray-500 hover:text-gray-700'}`}
                                        title="Vista de Tablero (Kanban)"
                                    >
                                        <ICONS.LayoutGrid />
                                    </button>
                                </div>
                            )}
                            <button 
                                onClick={fetchTickets}
                                className="text-sm text-teams-purple hover:underline"
                            >
                                Actualizar
                            </button>
                        </div>
                    </div>

                    {isLoading ? (
                        <div className="flex justify-center items-center py-12">
                            <div className="text-teams-purple animate-spin">
                                <ICONS.Spinner />
                            </div>
                            <span className="ml-2 text-gray-500">Cargando tickets...</span>
                        </div>
                    ) : (
                        viewMode === 'kanban' && isTechOrAdmin ? (
                            <KanbanBoard 
                                tickets={tickets} 
                                onStatusChange={handleStatusChange} 
                                onSelectTicket={handleSelectTicket}
                            />
                        ) : (
                            <TicketList 
                                tickets={tickets} 
                                onStatusChange={handleStatusChange} 
                                onSelectTicket={handleSelectTicket}
                                isLoading={isLoading} 
                                currentUser={user}
                            />
                        )
                    )}
                    </>
                )}

                {activeTab === Tab.NEW && (
                    <TicketForm 
                    onSubmit={handleCreateTicket} 
                    onCancel={() => setActiveTab(Tab.LIST)} 
                    />
                )}

                {activeTab === Tab.CHAT && (
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    <div className="md:col-span-2">
                        <ChatAssistant />
                    </div>
                    <div className="bg-white p-4 rounded-lg border border-gray-200 h-fit">
                        <h3 className="font-semibold mb-2 text-sm">Sobre Soporte IA</h3>
                        <p className="text-xs text-gray-500 mb-3">
                        Nuestro Asistente IA usa <strong>Gemini Pro</strong> para ayudar a diagnosticar problemas antes de enviar un ticket.
                        </p>
                        <ul className="text-xs text-gray-500 list-disc list-inside space-y-1">
                        <li><strong>Aprendizaje Automático:</strong> La IA conoce las soluciones de tickets pasados.</li>
                        <li><strong>Wiki Integrada:</strong> Consulta las FAQs antes de responder.</li>
                        <li>Haz preguntas técnicas</li>
                        <li>Soluciona errores de software</li>
                        </ul>
                    </div>
                    </div>
                )}

                {activeTab === Tab.WIKI && (
                    <WikiPanel />
                )}

                {activeTab === Tab.ADMIN && isAdmin && (
                    <AdminPanel />
                )}
            </>
          )}
        </div>
      </main>
    </div>
  );
}
